```rust
fn is_prime(n: u64) -> bool {
    if n < 2 {
        return false;
    }
    if n == 2 || n == 3 {
        return true;
    }
    if n % 2 == 0 || n % 3 == 0 {
        return false;
    }
    let mut i = 5;
    while i * i <= n {
        if n % i == 0 || n % (i + 2) == 0 {
            return false;
        }
        i += 6;
    }
    true
}

fn main() {
    let numbers = [0, 1, 2, 3, 4, 5, 16, 17, 19, 20, 9973];
    for &n in &numbers {
        println!("{} is prime? {}", n, is_prime(n));
    }
}
```

**How it works:**
- Quickly eliminates numbers less than 2, even numbers, and those divisible by 3.
- For odd numbers, only checks divisibility up to sqrt(n).
- Uses the 6k ± 1 optimization for efficiency.

