#[derive(Debug)]
enum NestedList {
    Elem(i32),
    List(Vec<NestedList>),
}

fn flatten(nested: &NestedList) -> Vec<i32> {
    let mut result = Vec::new();
    fn helper(nested: &NestedList, result: &mut Vec<i32>) {
        match nested {
            NestedList::Elem(val) => result.push(*val),
            NestedList::List(list) => {
                for item in list {
                    helper(item, result);
                }
            }
        }
    }
    helper(nested, &mut result);
    result
}

fn main() {
    let nested = NestedList::List(vec![
        NestedList::Elem(1),
        NestedList::List(vec![
            NestedList::Elem(2),
            NestedList::Elem(3),
        ]),
        NestedList::Elem(4),
        NestedList::List(vec![]),
        NestedList::List(vec![
            NestedList::Elem(5),
            NestedList::List(vec![
                NestedList::Elem(6),
            ]),
        ]),
    ]);

    let flat = flatten(&nested);
    println!("{:?}", flat); // Output: [1, 2, 3, 4, 5, 6]
}
```

**Explanation:**

- `NestedList` is an enum that can be an element (`Elem(i32)`) or a list of `NestedList`s.
- `flatten` recursively traverses the `NestedList`, collecting all elements into a flat `Vec<i32>`.
- `helper` is used for recursion.
- The `main` function constructs a nested structure and demonstrates flattening it.

