Certainly! Here's a complete, working implementation of an **LRU (Least Recently Used) Cache** in Rust using `HashMap` and a custom doubly-linked list for O(1) access and eviction:

```rust
use std::collections::HashMap;
use std::rc::{Rc, Weak};
use std::cell::{RefCell, Ref};

// Node for the doubly-linked list
struct Node<K, V> {
    key: K,
    value: V,
    prev: Option<Weak<RefCell<Node<K, V>>>>,
    next: Option<Rc<RefCell<Node<K, V>>>>,
}

impl<K, V> Node<K, V> {
    fn new(key: K, value: V) -> Rc<RefCell<Self>> {
        Rc::new(RefCell::new(Node {
            key,
            value,
            prev: None,
            next: None,
        }))
    }
}

pub struct LruCache<K: std::hash::Hash + Eq + Clone, V> {
    map: HashMap<K, Rc<RefCell<Node<K, V>>>>,
    capacity: usize,
    head: Option<Rc<RefCell<Node<K, V>>>>,
    tail: Option<Rc<RefCell<Node<K, V>>>>,
}

impl<K: std::hash::Hash + Eq + Clone, V> LruCache<K, V> {
    pub fn new(capacity: usize) -> Self {
        assert!(capacity > 0, "Capacity must be greater than zero");
        LruCache {
            map: HashMap::with_capacity(capacity),
            capacity,
            head: None,
            tail: None,
        }
    }

    pub fn get(&mut self, key: &K) -> Option<Ref<V>> {
        if let Some(node_rc) = self.map.get(key) {
            self.move_to_head(node_rc.clone());
            Some(Ref::map(node_rc.borrow(), |node| &node.value))
        } else {
            None
        }
    }

    pub fn put(&mut self, key: K, value: V) {
        if let Some(node_rc) = self.map.get(&key) {
            node_rc.borrow_mut().value = value;
            self.move_to_head(node_rc.clone());
        } else {
            if self.map.len() == self.capacity {
                self.evict_lru();
            }
            let new_node = Node::new(key.clone(), value);
            self.insert_at_head(new_node.clone());
            self.map.insert(key, new_node);
        }
    }

    fn move_to_head(&mut self, node: Rc<RefCell<Node<K, V>>>) {
        // If already at head, nothing to do.
        if let Some(head_rc) = &self.head {
            if Rc::ptr_eq(&node, head_rc) {
                return;
            }
        }

        // Detach node
        {
            let mut node_ref = node.borrow_mut();

            // prev
            if let Some(prev_weak) = node_ref.prev.take() {
                if let Some(prev_rc) = prev_weak.upgrade() {
                    prev_rc.borrow_mut().next = node_ref.next.clone();
                }
            }

            // next
            if let Some(next_rc) = node_ref.next.take() {
                next_rc.borrow_mut().prev = node_ref.prev.clone();
            } else {
                // If node has no next, it was the tail
                self.tail = node_ref.prev.as_ref().and_then(|w| w.upgrade());
            }
        }

        // Insert at head
        self.insert_at_head(node);
    }

    fn insert_at_head(&mut self, node: Rc<RefCell<Node<K, V>>>) {
        node.borrow_mut().prev = None;
        node.borrow_mut().next = self.head.clone();

        if let Some(old_head) = &self.head {
            old_head.borrow_mut().prev = Some(Rc::downgrade(&node));
        } else {
            // If head is None, this is the first node, set tail as well
            self.tail = Some(node.clone());
        }
        self.head = Some(node);
    }

    fn evict_lru(&mut self) {
        if let Some(tail_rc) = &self.tail {
            let tail_key = tail_rc.borrow().key.clone();
            // Detach tail
            if let Some(prev_weak) = &tail_rc.borrow().prev {
                if let Some(prev_rc) = prev_weak.upgrade() {
                    prev_rc.borrow_mut().next = None;
                    self.tail = Some(prev_rc);
                } else {
                    // No prev, so cache is empty after evict
                    self.head = None;
                    self.tail = None;
                }
            } else {
                // No prev, so cache is empty after evict
                self.head = None;
                self.tail = None;
            }
            self.map.remove(&tail_key);
        }
    }
}

// Example usage:
fn main() {
    let mut cache = LruCache::new(2);
    cache.put(1, "one");
    cache.put(2, "two");

    assert_eq!(*cache.get(&1).unwrap(), "one");

    cache.put(3, "three"); // evicts key 2

    assert!(cache.get(&2).is_none());
    assert_eq!(*cache.get(&3).unwrap(), "three");

    cache.put(4, "four"); // evicts key 1

    assert!(cache.get(&1).is_none());
    assert_eq!(*cache.get(&4).unwrap(), "four");
}
```

---

**How it works:**
- **map:** stores key to node pointer for O(1) lookup.
- **doubly-linked list:** tracks usage order, head = MRU, tail = LRU.
- **put:** inserts/updates, moves to head, evicts LRU if needed.
- **get:** moves found item to head (most recently used).
- **evict_lru:** removes tail node.

---

**This code is ready to copy, paste, and run!** You can change `K` and `V` as needed (as long as `K` implements `Hash + Eq + Clone`).

Certainly! Here's a complete Rust implementation for serializing and deserializing a binary tree. The code includes:

- A definition for the binary tree node (`TreeNode`).
- Serialization to a string (using BFS with level order traversal, representing `None` as `'null'`).
- Deserialization from such a string.

This design is similar to Leetcode style binary tree serialization.

---

```rust
use std::collections::VecDeque;

#[derive(Debug, PartialEq, Eq)]
pub struct TreeNode {
    pub val: i32,
    pub left: Option<Box<TreeNode>>,
    pub right: Option<Box<TreeNode>>,
}

impl TreeNode {
    pub fn new(val: i32) -> Self {
        TreeNode { val, left: None, right: None }
    }
}

// Serialize: level-order traversal, using "null" for empty nodes.
pub fn serialize(root: Option<Box<TreeNode>>) -> String {
    if root.is_none() {
        return String::from("[]");
    }

    let mut result = vec![];
    let mut queue = VecDeque::new();
    queue.push_back(root);

    while !queue.is_empty() {
        let node_opt = queue.pop_front().unwrap();
        if let Some(node) = node_opt {
            result.push(node.val.to_string());
            queue.push_back(node.left);
            queue.push_back(node.right);
        } else {
            result.push(String::from("null"));
        }
    }

    // Remove trailing "null"s
    while let Some(last) = result.last() {
        if last == "null" {
            result.pop();
        } else {
            break;
        }
    }

    format!("[{}]", result.join(","))
}

// Deserialize: build tree from string produced above
pub fn deserialize(data: String) -> Option<Box<TreeNode>> {
    let data = data.trim();
    if data == "[]" {
        return None;
    }

    let nodes: Vec<&str> = data.trim_matches(&['[', ']'][..]).split(',').collect();
    let mut idx = 0;

    let root_val = nodes[idx].parse::<i32>().ok()?;
    let root = Box::new(TreeNode::new(root_val));
    let mut queue = VecDeque::new();
    queue.push_back(root);

    idx += 1;

    while !queue.is_empty() {
        let mut node = queue.pop_front().unwrap();

        // Left child
        if idx < nodes.len() {
            if nodes[idx] != "null" {
                let left_val = nodes[idx].parse::<i32>().ok()?;
                let left_node = Box::new(TreeNode::new(left_val));
                queue.push_back(left_node);
                node.left = Some(left_node);
            }
            idx += 1;
        }

        // Right child
        if idx < nodes.len() {
            if nodes[idx] != "null" {
                let right_val = nodes[idx].parse::<i32>().ok()?;
                let right_node = Box::new(TreeNode::new(right_val));
                queue.push_back(right_node);
                node.right = Some(right_node);
            }
            idx += 1;
        }
    }

    Some(root)
}

// --- Testing ---

fn main() {
    // Example tree:
    //     1
    //    / \
    //   2   3
    //      / \
    //     4   5
    let mut root = Box::new(TreeNode::new(1));
    root.left = Some(Box::new(TreeNode::new(2)));
    let mut right = Box::new(TreeNode::new(3));
    right.left = Some(Box::new(TreeNode::new(4)));
    right.right = Some(Box::new(TreeNode::new(5)));
    root.right = Some(right);

    let serialized = serialize(Some(root));
    println!("Serialized: {}", serialized); // Should print: [1,2,3,null,null,4,5]

    let deserialized = deserialize(serialized.clone());
    let serialized_again = serialize(deserialized);
    println!("Serialized again: {}", serialized_again); // Should match original serialization

    assert_eq!(serialized, serialized_again);
}

```

---

**How it works:**

- **Serialization:**  
  Traverses the tree using BFS, appending values or "null" to the output. Trailing "null"s are removed for brevity.
- **Deserialization:**  
  Splits the string into nodes, builds the tree using BFS (using a queue).

**You can copy-paste this code and run it. The assertion in `main` ensures correct round-trip (serialize -> deserialize -> serialize).**

Certainly! Here is a complete, working implementation of a Trie data structure in Rust.
This implementation supports insertion, search, and deletion of words.

```rust
use std::collections::HashMap;

#[derive(Debug, Default)]
struct TrieNode {
    children: HashMap<char, TrieNode>,
    is_end_of_word: bool,
}

#[derive(Debug, Default)]
pub struct Trie {
    root: TrieNode,
}

impl Trie {
    /// Creates a new Trie.
    pub fn new() -> Self {
        Trie {
            root: TrieNode::default(),
        }
    }

    /// Inserts a word into the trie.
    pub fn insert(&mut self, word: &str) {
        let mut node = &mut self.root;
        for c in word.chars() {
            node = node.children.entry(c).or_insert_with(TrieNode::default);
        }
        node.is_end_of_word = true;
    }

    /// Returns true if the word is in the trie.
    pub fn search(&self, word: &str) -> bool {
        let mut node = &self.root;
        for c in word.chars() {
            match node.children.get(&c) {
                Some(next_node) => node = next_node,
                None => return false,
            }
        }
        node.is_end_of_word
    }

    /// Returns true if there is any word in the trie that starts with the given prefix.
    pub fn starts_with(&self, prefix: &str) -> bool {
        let mut node = &self.root;
        for c in prefix.chars() {
            match node.children.get(&c) {
                Some(next_node) => node = next_node,
                None => return false,
            }
        }
        true
    }

    /// Removes a word from the trie. Returns true if the word was removed.
    pub fn remove(&mut self, word: &str) -> bool {
        Self::remove_inner(&mut self.root, word, 0)
    }

    fn remove_inner(node: &mut TrieNode, word: &str, depth: usize) -> bool {
        if depth == word.len() {
            if node.is_end_of_word {
                node.is_end_of_word = false;
                // If node has no children, signal for removal.
                return node.children.is_empty();
            }
            return false;
        }
        let c = word.chars().nth(depth).unwrap();
        if let Some(child) = node.children.get_mut(&c) {
            let should_remove_child = Self::remove_inner(child, word, depth + 1);
            if should_remove_child {
                node.children.remove(&c);
                // If current node is not end of another word and has no children, signal for removal.
                return !node.is_end_of_word && node.children.is_empty();
            }
        }
        false
    }
}

fn main() {
    let mut trie = Trie::new();

    trie.insert("hello");
    trie.insert("helium");
    trie.insert("hero");
    trie.insert("her");
    trie.insert("hey");

    println!("Search 'hello': {}", trie.search("hello")); // true
    println!("Search 'her': {}", trie.search("her"));     // true
    println!("Search 'hey': {}", trie.search("hey"));     // true
    println!("Search 'he': {}", trie.search("he"));       // false

    println!("Starts with 'he': {}", trie.starts_with("he")); // true
    println!("Starts with 'hel': {}", trie.starts_with("hel")); // true
    println!("Starts with 'ha': {}", trie.starts_with("ha")); // false

    trie.remove("hero");
    println!("Search 'hero' after remove: {}", trie.search("hero")); // false
    println!("Search 'her' after remove: {}", trie.search("her"));   // true
}
```

