Certainly! Here's a complete, **working Rust implementation** of Dijkstra's shortest path algorithm. This code uses a min-heap priority queue (via `BinaryHeap`) and represents a weighted, directed graph with adjacency lists. It finds shortest paths from a given start node.

---

```rust
use std::collections::{BinaryHeap, HashMap};
use std::cmp::Ordering;

// --------------------- Graph Structure ---------------------
#[derive(Debug)]
struct Edge {
    node: usize,
    weight: u32,
}

type Graph = Vec<Vec<Edge>>;

// ------------------- Dijkstra's Algorithm ------------------

#[derive(Copy, Clone, Eq, PartialEq)]
struct State {
    cost: u32,
    position: usize,
}

// Reverse ordering for BinaryHeap (min-heap)
impl Ord for State {
    fn cmp(&self, other: &Self) -> Ordering {
        other
            .cost
            .cmp(&self.cost)
            .then_with(|| self.position.cmp(&other.position))
    }
}

impl PartialOrd for State {
    fn partial_cmp(&self, other: &State) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

// Returns shortest distances from start to all nodes
fn dijkstra(graph: &Graph, start: usize) -> Vec<u32> {
    let n = graph.len();
    let mut dist = vec![u32::MAX; n];
    let mut heap = BinaryHeap::new();

    // Start node distance = 0
    dist[start] = 0;
    heap.push(State {
        cost: 0,
        position: start,
    });

    while let Some(State { cost, position }) = heap.pop() {
        // If found a better way already, skip
        if cost > dist[position] {
            continue;
        }

        // For each neighbor
        for edge in &graph[position] {
            let next = State {
                cost: cost + edge.weight,
                position: edge.node,
            };

            // If next path is shorter, update and push to heap
            if next.cost < dist[next.position] {
                dist[next.position] = next.cost;
                heap.push(next);
            }
        }
    }

    dist
}

// -------------------------- Demo --------------------------

fn main() {
    // Create a simple graph:
    // Node 0: [(1, 2), (2, 4)]
    // Node 1: [(2, 1), (3, 7)]
    // Node 2: [(3, 3)]
    // Node 3: []

    let graph = vec![
        vec![Edge { node: 1, weight: 2 }, Edge { node: 2, weight: 4 }],
        vec![Edge { node: 2, weight: 1 }, Edge { node: 3, weight: 7 }],
        vec![Edge { node: 3, weight: 3 }],
        vec![],
    ];

    let start = 0;
    let dist = dijkstra(&graph, start);

    for (i, d) in dist.iter().enumerate() {
        if *d == u32::MAX {
            println!("Node {} is unreachable from node {}", i, start);
        } else {
            println!("Distance from node {} to node {}: {}", start, i, d);
        }
    }
}
```

---

**How it works:**  
- The `Edge` struct represents a directed edge with a target `node` and a `weight`.
- The graph is a vector of adjacency lists: each node has a vector of its outgoing edges.
- Dijkstra's algorithm maintains a distance vector and a min-heap (via `BinaryHeap` and custom order).
- The demo uses a small graph and prints the shortest distances from node `0` to all other nodes.

