Here is a complete implementation of a **bounded blocking queue** in Rust using `Arc`, `Mutex`, and `Condvar` from the standard library. This implementation supports multiple producers and consumers, **blocking** on `push` when full and `pop` when empty.

```rust
use std::collections::VecDeque;
use std::sync::{Arc, Mutex, Condvar};
use std::time::Duration;

/// A bounded, thread-safe blocking queue.
pub struct BoundedBlockingQueue<T> {
    queue: Mutex<VecDeque<T>>,
    capacity: usize,
    not_full: Condvar,
    not_empty: Condvar,
}

impl<T> BoundedBlockingQueue<T> {
    /// Create a new bounded blocking queue with the given capacity.
    pub fn new(capacity: usize) -> Arc<Self> {
        assert!(capacity > 0);
        Arc::new(Self {
            queue: Mutex::new(VecDeque::with_capacity(capacity)),
            capacity,
            not_full: Condvar::new(),
            not_empty: Condvar::new(),
        })
    }

    /// Push an element into the queue, blocking if the queue is full.
    pub fn push(&self, item: T) {
        let mut queue_guard = self.queue.lock().unwrap();
        while queue_guard.len() == self.capacity {
            queue_guard = self.not_full.wait(queue_guard).unwrap();
        }
        queue_guard.push_back(item);
        // Wake up potential popper(s).
        self.not_empty.notify_one();
    }

    /// Pop an element from the queue, blocking if the queue is empty.
    pub fn pop(&self) -> T {
        let mut queue_guard = self.queue.lock().unwrap();
        while queue_guard.is_empty() {
            queue_guard = self.not_empty.wait(queue_guard).unwrap();
        }
        let item = queue_guard.pop_front().unwrap();
        // Wake up potential pusher(s).
        self.not_full.notify_one();
        item
    }

    /// Try to push an item, returning Err(item) if queue is full.
    pub fn try_push(&self, item: T) -> Result<(), T> {
        let mut queue_guard = self.queue.lock().unwrap();
        if queue_guard.len() == self.capacity {
            return Err(item);
        }
        queue_guard.push_back(item);
        self.not_empty.notify_one();
        Ok(())
    }

    /// Try to pop an item, returning None if queue is empty.
    pub fn try_pop(&self) -> Option<T> {
        let mut queue_guard = self.queue.lock().unwrap();
        if queue_guard.is_empty() {
            return None;
        }
        let item = queue_guard.pop_front().unwrap();
        self.not_full.notify_one();
        Some(item)
    }

    /// Get current length (for debug/testing).
    pub fn len(&self) -> usize {
        let queue_guard = self.queue.lock().unwrap();
        queue_guard.len()
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::thread;

    #[test]
    fn test_basic() {
        let q = BoundedBlockingQueue::new(2);

        assert_eq!(q.len(), 0);
        q.push(1);
        assert_eq!(q.len(), 1);
        q.push(2);
        assert_eq!(q.len(), 2);

        assert_eq!(q.try_push(3), Err(3));
        assert_eq!(q.pop(), 1);
        assert_eq!(q.len(), 1);

        assert_eq!(q.pop(), 2);
        assert_eq!(q.len(), 0);

        assert_eq!(q.try_pop(), None);
        q.push(42);
        assert_eq!(q.try_pop(), Some(42));
    }

    #[test]
    fn test_multi_thread() {
        let q = BoundedBlockingQueue::new(2);

        let q_clone = q.clone();
        let handle = thread::spawn(move || {
            // Block until item arrives
            let n = q_clone.pop();
            assert_eq!(n, 123);
            // Block until item arrives
            let n = q_clone.pop();
            assert_eq!(n, 456);
        });

        thread::sleep(Duration::from_millis(100));
        q.push(123);
        q.push(456);
        handle.join().unwrap();
    }

    #[test]
    fn test_blocking_push() {
        let q = BoundedBlockingQueue::new(1);

        q.push(7);
        let q_clone = q.clone();
        let handle = thread::spawn(move || {
            // Will block until main thread pops an item.
            q_clone.push(8);
        });

        thread::sleep(Duration::from_millis(100));
        assert_eq!(q.pop(), 7);
        handle.join().unwrap();
        assert_eq!(q.pop(), 8);
    }
}

fn main() {
    let queue = BoundedBlockingQueue::new(3);

    let queue_cloned = queue.clone();
    std::thread::spawn(move || {
        for i in 0..5 {
            println!("Producer pushing {}", i);
            queue_cloned.push(i);
            println!("Producer pushed {}", i);
        }
    });

    // Main thread pops five values.
    for _ in 0..5 {
        let value = queue.pop();
        println!("Consumer popped {}", value);
    }
}
```

**Key points:**

- Use `Arc<BoundedBlockingQueue<T>>` for sharing between threads.
- `push()` and `pop()` block as described.
- Capacity is enforced.
- Demo and tests included.

