Copy and paste this into a Rust file (e.g., `main.rs`) in a cargo project. Run with `cargo run`. It will read expressions from stdin and output the result.

---

```rust
use std::io::{self, BufRead};

#[derive(Debug, Clone, PartialEq)]
enum Token {
    Number(f64),
    Plus,
    Minus,
    Mul,
    Div,
    LParen,
    RParen,
    End,
}

struct Lexer<'a> {
    input: &'a str,
    pos: usize,
}

impl<'a> Lexer<'a> {
    fn new(input: &'a str) -> Self {
        Lexer { input, pos: 0 }
    }

    fn next_token(&mut self) -> Token {
        let bytes = self.input.as_bytes();
        // Skip whitespace
        while self.pos < bytes.len() && bytes[self.pos].is_ascii_whitespace() {
            self.pos += 1;
        }
        if self.pos >= bytes.len() {
            return Token::End;
        }
        let c = bytes[self.pos];
        match c {
            b'+' => { self.pos += 1; Token::Plus }
            b'-' => { self.pos += 1; Token::Minus }
            b'*' => { self.pos += 1; Token::Mul }
            b'/' => { self.pos += 1; Token::Div }
            b'(' => { self.pos += 1; Token::LParen }
            b')' => { self.pos += 1; Token::RParen }
            b'0'..=b'9' | b'.' => {
                let start = self.pos;
                while self.pos < bytes.len() && 
                      (bytes[self.pos].is_ascii_digit() || bytes[self.pos] == b'.') {
                    self.pos += 1;
                }
                Token::Number(self.input[start..self.pos].parse::<f64>().unwrap())
            }
            _ => panic!("Invalid character: {}", c as char),
        }
    }
}

struct Parser<'a> {
    lexer: Lexer<'a>,
    current: Token,
}

impl<'a> Parser<'a> {
    fn new(input: &'a str) -> Self {
        let mut lexer = Lexer::new(input);
        let current = lexer.next_token();
        Parser { lexer, current }
    }

    fn eat(&mut self, expected: Token) {
        if self.current == expected {
            self.current = self.lexer.next_token();
        } else {
            panic!("Expected {:?}, found {:?}", expected, self.current);
        }
    }

    // expr = term {(+|-) term}
    fn expr(&mut self) -> f64 {
        let mut value = self.term();
        while self.current == Token::Plus || self.current == Token::Minus {
            match self.current.clone() {
                Token::Plus => {
                    self.eat(Token::Plus);
                    value += self.term();
                }
                Token::Minus => {
                    self.eat(Token::Minus);
                    value -= self.term();
                }
                _ => unreachable!(),
            }
        }
        value
    }

    // term = factor {(*|/) factor}
    fn term(&mut self) -> f64 {
        let mut value = self.factor();
        while self.current == Token::Mul || self.current == Token::Div {
            match self.current.clone() {
                Token::Mul => {
                    self.eat(Token::Mul);
                    value *= self.factor();
                }
                Token::Div => {
                    self.eat(Token::Div);
                    value /= self.factor();
                }
                _ => unreachable!(),
            }
        }
        value
    }

    // factor = number | '(' expr ')'
    fn factor(&mut self) -> f64 {
        match self.current.clone() {
            Token::Number(n) => {
                self.eat(Token::Number(n));
                n
            }
            Token::LParen => {
                self.eat(Token::LParen);
                let value = self.expr();
                self.eat(Token::RParen);
                value
            }
            Token::Minus => {
                self.eat(Token::Minus);
                -self.factor()
            }
            _ => panic!("Unexpected token: {:?}", self.current),
        }
    }

    fn parse(&mut self) -> f64 {
        let result = self.expr();
        if self.current != Token::End {
            panic!("Unexpected input at end: {:?}", self.current);
        }
        result
    }
}

fn main() {
    println!("Enter expressions (Ctrl+D to exit):");
    let stdin = io::stdin();

    for line in stdin.lock().lines() {
        let expr = line.unwrap();
        if expr.trim().is_empty() { continue; }
        let mut parser = Parser::new(&expr);
        let result = parser.parse();
        println!("= {}", result);
    }
}
```

