Certainly! Here is a **basic regex matcher in Rust**. This implementation supports:

- Character matching (e.g., "a")
- Dot (`.`) wildcard (matches any character)
- Star (`*`) for zero-or-more repetitions (on the preceding character)
- No parenthesis, brackets, or alternation

## Implementation

```rust
fn is_match(s: &str, p: &str) -> bool {
    fn helper(s: &[u8], p: &[u8]) -> bool {
        if p.is_empty() {
            return s.is_empty();
        }

        // Check if first char matches
        let first_match = !s.is_empty() && (p[0] == b'.' || p[0] == s[0]);

        // Handle star
        if p.len() >= 2 && p[1] == b'*' {
            // '*' can match zero or more of p[0]
            // 1. Skip star: helper(s, &p[2..])
            // 2. Use star: helper(&s[1..], p) if first_match
            helper(s, &p[2..]) || (first_match && helper(&s[1..], p))
        } else {
            // Regular match
            first_match && helper(&s[1..], &p[1..])
        }
    }
    helper(s.as_bytes(), p.as_bytes())
}

fn main() {
    let tests = [
        ("aa", "a", false),
        ("aa", "a*", true),
        ("ab", ".*", true),
        ("aab", "c*a*b", true),
        ("mississippi", "mis*is*p*.", false),
        ("", ".*", true),
        ("", "", true),
        ("", "a*", true),
    ];

    for &(text, pat, expected) in &tests {
        let result = is_match(text, pat);
        println!(
            "is_match({:?}, {:?}) = {}, expected {}",
            text, pat, result, expected
        );
        assert_eq!(result, expected);
    }
}
```

