Certainly! Here is a **complete, working Rust implementation** of the **Longest Common Subsequence (LCS)** algorithm. This implementation computes the LCS string itself, not just its length.

```rust
fn longest_common_subsequence(a: &str, b: &str) -> String {
    let a_chars: Vec<char> = a.chars().collect();
    let b_chars: Vec<char> = b.chars().collect();
    let m = a_chars.len();
    let n = b_chars.len();

    // DP matrix: dp[i][j] is length of LCS of a[0..i] & b[0..j]
    let mut dp = vec![vec![0; n + 1]; m + 1];

    // Build DP table
    for i in 0..m {
        for j in 0..n {
            if a_chars[i] == b_chars[j] {
                dp[i + 1][j + 1] = dp[i][j] + 1;
            } else {
                dp[i + 1][j + 1] = dp[i + 1][j].max(dp[i][j + 1]);
            }
        }
    }

    // Reconstruct LCS
    let mut lcs = Vec::new();
    let mut i = m;
    let mut j = n;
    while i > 0 && j > 0 {
        if a_chars[i - 1] == b_chars[j - 1] {
            lcs.push(a_chars[i - 1]);
            i -= 1;
            j -= 1;
        } else if dp[i - 1][j] >= dp[i][j - 1] {
            i -= 1;
        } else {
            j -= 1;
        }
    }
    lcs.reverse();
    lcs.into_iter().collect()
}

fn main() {
    let s1 = "AGGTAB";
    let s2 = "GXTXAYB";
    let lcs = longest_common_subsequence(s1, s2);
    println!("LCS of '{}' and '{}' is '{}'", s1, s2, lcs); // Should output "GTAB"
}

```

---

**Explanation:**
- Uses dynamic programming to first build the table for LCS lengths.
- Then reconstructs the actual LCS by tracing the table backward.
- Works for any string input.
- Example in `main` prints the LCS for two test strings.

