```rust
use std::collections::HashSet;
use std::net::SocketAddr;
use std::sync::Arc;
use std::time::Duration;

use rand::Rng;
use serde::{Deserialize, Serialize};
use tokio::net::UdpSocket;
use tokio::sync::Mutex;
use tokio::time::timeout;

#[derive(Debug, Clone, Serialize, Deserialize)]
enum Message {
    RequestVote {
        term: u64,
        candidate_id: usize,
    },
    RequestVoteReply {
        term: u64,
        vote_granted: bool,
        from_id: usize,
    },
    AppendEntries {
        term: u64,
        leader_id: usize,
    },
    AppendEntriesReply {
        term: u64,
        from_id: usize,
    },
}

#[derive(Debug, PartialEq)]
enum State {
    Follower,
    Candidate,
    Leader,
}

struct RaftNode {
    id: usize,
    peers: Vec<SocketAddr>,
    state: State,
    current_term: u64,
    voted_for: Option<usize>,
    votes_received: HashSet<usize>,
    socket: Arc<UdpSocket>,
}

impl RaftNode {
    fn new(id: usize, peers: Vec<SocketAddr>, socket: Arc<UdpSocket>) -> Self {
        RaftNode {
            id,
            peers,
            state: State::Follower,
            current_term: 0,
            voted_for: None,
            votes_received: HashSet::new(),
            socket,
        }
    }

    async fn run(self: Arc<Mutex<Self>>) {
        let mut election_timeout = Self::rand_election_timeout();

        loop {
            {
                let mut node = self.lock().await;
                match node.state {
                    State::Follower => {
                        println!("[{}] State: Follower, term {}", node.id, node.current_term);
                    }
                    State::Candidate => {
                        println!("[{}] State: Candidate, term {}", node.id, node.current_term);
                    }
                    State::Leader => {
                        println!("[{}] State: Leader, term {}", node.id, node.current_term);
                    }
                }
            }
            // Wait for election timeout, or reset if AppendEntries is received
            let election_wait = timeout(election_timeout, Self::receive(self.clone()));
            if let Ok(msg) = election_wait.await {
                if let Some((msg, from)) = msg {
                    Self::handle_message(self.clone(), msg, from).await;
                }
            } else {
                // Election timeout expired, initiate election
                let mut node = self.lock().await;
                if node.state != State::Leader {
                    node.current_term += 1;
                    node.state = State::Candidate;
                    node.voted_for = Some(node.id);
                    node.votes_received.clear();
                    node.votes_received.insert(node.id);
                    println!("[{}] Election timeout. Starting election for term {}", node.id, node.current_term);
                    drop(node);
                    Self::send_request_vote(self.clone()).await;
                }
                // Set new random timeout
                election_timeout = Self::rand_election_timeout();
            }
        }
    }

    async fn receive(self: Arc<Mutex<Self>>) -> Option<(Message, SocketAddr)> {
        let buf_size = 1024;
        let mut buf = vec![0u8; buf_size];
        let socket;
        {
            let node = self.lock().await;
            socket = node.socket.clone();
        }

        let recv = socket.recv_from(&mut buf).await;
        match recv {
            Ok((len, from)) => {
                let msg: Result<Message, _> = serde_json::from_slice(&buf[..len]);
                match msg {
                    Ok(message) => Some((message, from)),
                    Err(_) => None,
                }
            }
            Err(_) => None,
        }
    }

    async fn handle_message(self: Arc<Mutex<Self>>, msg: Message, from: SocketAddr) {
        let mut node = self.lock().await;
        match msg {
            Message::RequestVote { term, candidate_id } => {
                if term > node.current_term {
                    node.current_term = term;
                    node.state = State::Follower;
                    node.voted_for = None;
                }
                let mut vote_granted = false;
                if term == node.current_term && node.voted_for.is_none() {
                    node.voted_for = Some(candidate_id);
                    vote_granted = true;
                    println!("[{}] Voted for {} in term {}", node.id, candidate_id, term);
                }
                let reply = Message::RequestVoteReply {
                    term: node.current_term,
                    vote_granted,
                    from_id: node.id,
                };
                let socket = node.socket.clone();
                drop(node);
                let reply_bytes = serde_json::to_vec(&reply).unwrap();
                let _ = socket.send_to(&reply_bytes, from).await;
            }
            Message::RequestVoteReply { term, vote_granted, from_id } => {
                if term > node.current_term {
                    node.current_term = term;
                    node.state = State::Follower;
                    node.voted_for = None;
                    node.votes_received.clear();
                    return;
                }
                if node.state != State::Candidate || term < node.current_term {
                    return;
                }
                if vote_granted {
                    node.votes_received.insert(from_id);
                    let quorum = (node.peers.len() + 1) / 2 + 1;
                    if node.votes_received.len() >= quorum {
                        node.state = State::Leader;
                        println!("[{}] Became Leader in term {}", node.id, node.current_term);
                        drop(node);
                        tokio::spawn(Self::heartbeat(self.clone()));
                    }
                }
            }
            Message::AppendEntries { term, leader_id } => {
                if term >= node.current_term {
                    node.current_term = term;
                    node.state = State::Follower;
                    node.voted_for = None;
                }
                // Respond to heartbeat
                let reply = Message::AppendEntriesReply {
                    term: node.current_term,
                    from_id: node.id,
                };
                let socket = node.socket.clone();
                drop(node);
                let reply_bytes = serde_json::to_vec(&reply).unwrap();
                let _ = socket.send_to(&reply_bytes, from).await;
            }
            Message::AppendEntriesReply { .. } => {
                // We don't process heartbeat replies. Only heartbeat to followers.
            }
        }
    }

    async fn send_request_vote(self: Arc<Mutex<Self>>) {
        let node = self.lock().await;
        let msg = Message::RequestVote {
            term: node.current_term,
            candidate_id: node.id,
        };
        let msg_bytes = serde_json::to_vec(&msg).unwrap();
        let socket = node.socket.clone();

        for peer in &node.peers {
            let _ = socket.send_to(&msg_bytes, peer).await;
        }
    }

    async fn heartbeat(self: Arc<Mutex<Self>>) {
        loop {
            let node = self.lock().await;
            if node.state != State::Leader {
                return;
            }
            let msg = Message::AppendEntries {
                term: node.current_term,
                leader_id: node.id,
            };
            let msg_bytes = serde_json::to_vec(&msg).unwrap();
            let socket = node.socket.clone();
            for peer in &node.peers {
                let _ = socket.send_to(&msg_bytes, peer).await;
            }
            drop(node);
            tokio::time::sleep(Duration::from_millis(300)).await;
        }
    }

    fn rand_election_timeout() -> Duration {
        let mut rng = rand::thread_rng();
        let ms = rng.gen_range(800..=1500);
        Duration::from_millis(ms)
    }
}

#[tokio::main]
async fn main() {
    // Args: id, comma-separated peer addresses, own address
    let args: Vec<String> = std::env::args().collect();
    if args.len() != 4 {
        eprintln!("Usage: {} <id> <peer_addr1,peer_addr2,...> <bind_addr>", args[0]);
        std::process::exit(1);
    }

    let id: usize = args[1].parse().unwrap();
    let peers: Vec<SocketAddr> = args[2].split(',').map(|s| s.parse().unwrap()).collect();
    let bind_addr: SocketAddr = args[3].parse().unwrap();

    let socket = Arc::new(UdpSocket::bind(bind_addr).await.unwrap());
    let node = Arc::new(Mutex::new(RaftNode::new(id, peers, socket)));
    node.clone().run().await;
}
```

