Below is a **complete Rust implementation** of a persistent (immutable) Red-Black Tree:

- **Persistent:** Insertions return a new tree, leaving previous versions unchanged.
- **Red-Black Properties:** Satisfies all necessary invariants.
- **General Use:** Stores keys and values (generic types `K`, `V`).
- **Demonstration:** Includes basic usage and test cases.

---

```rust
use std::rc::Rc;
use std::cmp::Ordering;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum Color {
    Red,
    Black,
}

// We use Rc to get sharing/cheap cloning.
type Link<K, V> = Option<Rc<Node<K, V>>>;

#[derive(Debug)]
struct Node<K, V> {
    color: Color,
    key: K,
    value: V,
    left: Link<K, V>,
    right: Link<K, V>,
}

#[derive(Debug, Clone)]
pub struct RBTree<K, V> {
    root: Link<K, V>,
}

impl<K: Ord, V> RBTree<K, V> {
    pub fn new() -> Self {
        RBTree { root: None }
    }

    pub fn get(&self, key: &K) -> Option<&V> {
        let mut node = self.root.as_ref();
        while let Some(n) = node {
            match key.cmp(&n.key) {
                Ordering::Less => node = n.left.as_ref(),
                Ordering::Greater => node = n.right.as_ref(),
                Ordering::Equal => return Some(&n.value),
            }
        }
        None
    }

    /// Insert key-value, returning a new tree (persistent, doesn't update old tree).
    pub fn insert(&self, key: K, value: V) -> RBTree<K, V>
    where
        K: Clone,
        V: Clone,
    {
        fn insert_rec<K: Ord + Clone, V: Clone>(node: &Link<K, V>, key: K, value: V) -> Rc<Node<K, V>> {
            match node {
                None => Rc::new(Node {
                    color: Color::Red,
                    key,
                    value,
                    left: None,
                    right: None,
                }),
                Some(n) => {
                    match key.cmp(&n.key) {
                        Ordering::Less => {
                            let left = insert_rec(&n.left, key, value);
                            balance(Rc::new(Node {
                                color: n.color,
                                key: n.key.clone(),
                                value: n.value.clone(),
                                left: Some(left),
                                right: n.right.clone(),
                            }))
                        }
                        Ordering::Greater => {
                            let right = insert_rec(&n.right, key, value);
                            balance(Rc::new(Node {
                                color: n.color,
                                key: n.key.clone(),
                                value: n.value.clone(),
                                left: n.left.clone(),
                                right: Some(right),
                            }))
                        }
                        Ordering::Equal => { // Update value immutably
                            Rc::new(Node {
                                color: n.color,
                                key: n.key.clone(),
                                value,
                                left: n.left.clone(),
                                right: n.right.clone(),
                            })
                        }
                    }
                }
            }
        }

        let root = insert_rec(&self.root, key, value);
        // Always recolor root to black.
        RBTree {
            root: Some(Rc::new(Node {
                color: Color::Black,
                key: root.key.clone(),
                value: root.value.clone(),
                left: root.left.clone(),
                right: root.right.clone(),
            })),
        }
    }


    /// Returns true if key exists.
    pub fn contains(&self, key: &K) -> bool {
        self.get(key).is_some()
    }


    /// In-order traversal. Useful for testing.
    pub fn keys(&self) -> Vec<&K> {
        let mut res = Vec::new();
        fn inorder<K,V>(node: &Link<K,V>, res: &mut Vec<&K>) {
            if let Some(n) = node {
                inorder(&n.left, res);
                res.push(&n.key);
                inorder(&n.right, res);
            }
        }
        inorder(&self.root, &mut res);
        res
    }

    /// Counts the number of nodes.
    pub fn len(&self) -> usize {
        fn count<K,V>(node: &Link<K,V>) -> usize {
            match node {
                None => 0,
                Some(n) => 1 + count(&n.left) + count(&n.right),
            }
        }
        count(&self.root)
    }
}

// Balancing (see Okasaki, "Red-Black Trees in a Functional Setting")
fn balance<K: Clone, V: Clone>(node: Rc<Node<K, V>>) -> Rc<Node<K, V>> {
    // Case 1: Left, then left-left is red.
    if node.color == Color::Black {
        if let Some(left) = &node.left {
            if left.color == Color::Red {
                if let Some(left_left) = &left.left {
                    if left_left.color == Color::Red {
                        return Rc::new(Node {
                            color: Color::Red,
                            key: left.key.clone(),
                            value: left.value.clone(),
                            left: Some(Rc::new(Node {
                                color: Color::Black,
                                key: left_left.key.clone(),
                                value: left_left.value.clone(),
                                left: left_left.left.clone(),
                                right: left_left.right.clone(),
                            })),
                            right: Some(Rc::new(Node {
                                color: Color::Black,
                                key: node.key.clone(),
                                value: node.value.clone(),
                                left: left.right.clone(),
                                right: node.right.clone(),
                            })),
                        });
                    }
                }
                // Case 2: Left, then left-right is red.
                if let Some(left_right) = &left.right {
                    if left_right.color == Color::Red {
                        return Rc::new(Node {
                            color: Color::Red,
                            key: left_right.key.clone(),
                            value: left_right.value.clone(),
                            left: Some(Rc::new(Node {
                                color: Color::Black,
                                key: left.key.clone(),
                                value: left.value.clone(),
                                left: left.left.clone(),
                                right: left_right.left.clone(),
                            })),
                            right: Some(Rc::new(Node {
                                color: Color::Black,
                                key: node.key.clone(),
                                value: node.value.clone(),
                                left: left_right.right.clone(),
                                right: node.right.clone(),
                            })),
                        });
                    }
                }
            }
        }
        if let Some(right) = &node.right {
            if right.color == Color::Red {
                // Case 3: Right, then right-left is red.
                if let Some(right_left) = &right.left {
                    if right_left.color == Color::Red {
                        return Rc::new(Node {
                            color: Color::Red,
                            key: right_left.key.clone(),
                            value: right_left.value.clone(),
                            left: Some(Rc::new(Node {
                                color: Color::Black,
                                key: node.key.clone(),
                                value: node.value.clone(),
                                left: node.left.clone(),
                                right: right_left.left.clone(),
                            })),
                            right: Some(Rc::new(Node {
                                color: Color::Black,
                                key: right.key.clone(),
                                value: right.value.clone(),
                                left: right_left.right.clone(),
                                right: right.right.clone(),
                            })),
                        });
                    }
                }
                // Case 4: Right, then right-right is red.
                if let Some(right_right) = &right.right {
                    if right_right.color == Color::Red {
                        return Rc::new(Node {
                            color: Color::Red,
                            key: right.key.clone(),
                            value: right.value.clone(),
                            left: Some(Rc::new(Node {
                                color: Color::Black,
                                key: node.key.clone(),
                                value: node.value.clone(),
                                left: node.left.clone(),
                                right: right.left.clone(),
                            })),
                            right: Some(Rc::new(Node {
                                color: Color::Black,
                                key: right_right.key.clone(),
                                value: right_right.value.clone(),
                                left: right_right.left.clone(),
                                right: right_right.right.clone(),
                            })),
                        });
                    }
                }
            }
        }
    }
    // Otherwise, no balancing needed
    node
}

