**You may extend this simulation for more processes or real networking. This code is simple, illustrates the Lamport timestamp usage, and compiles/runs successfully with Rust stable.**

Certainly! Below is a **complete, idiomatic Rust implementation of a Skip List** supporting insert, search, and delete for generic key/value pairs (`K: Ord, V`). This code is self-contained and ready to run.

### Features

- Generic over key (`K: Ord`) and value (`V`)
- Random height with `rand` crate
- Insert, search, and remove operations
- Clear `SkipList` interface

### Dependencies

You'll need [`rand`](https://crates.io/crates/rand):

```toml
# Cargo.toml
[dependencies]
rand = "0.8"
```

---

## Skip List Code

```rust
use rand::prelude::*;
use std::cmp::Ordering;
use std::ptr;

const MAX_HEIGHT: usize = 16;
const P: f64 = 0.5;

/// A node in the skip list
struct Node<K, V> {
    key: K,
    value: V,
    next: Vec<*mut Node<K, V>>,
}

impl<K, V> Node<K, V> {
    fn new(key: K, value: V, height: usize) -> Self {
        Node {
            key,
            value,
            next: vec![ptr::null_mut(); height],
        }
    }

    fn height(&self) -> usize {
        self.next.len()
    }
}

pub struct SkipList<K, V> {
    head: *mut Node<K, V>,
    height: usize,
    len: usize,
}

impl<K: Ord, V> SkipList<K, V> {
    pub fn new() -> Self {
        let head = Box::into_raw(Box::new(Node {
            key: unsafe { std::mem::zeroed() }, // dummy
            value: unsafe { std::mem::zeroed() }, // dummy
            next: vec![ptr::null_mut(); MAX_HEIGHT],
        }));
        SkipList { head, height: 1, len: 0 }
    }

    fn random_height() -> usize {
        let mut height = 1;
        let mut rng = thread_rng();
        while height < MAX_HEIGHT && rng.gen::<f64>() < P {
            height += 1;
        }
        height
    }

    pub fn insert(&mut self, key: K, value: V) -> bool {
        let mut update = vec![self.head; MAX_HEIGHT];
        let mut curr = self.head;

        unsafe {
            for i in (0..self.height).rev() {
                while !(*curr).next[i].is_null() && (*(*curr).next[i]).key < key {
                    curr = (*curr).next[i];
                }
                update[i] = curr;
            }

            // Check for existence
            if !(*curr).next[0].is_null() && (*(*curr).next[0]).key == key {
                (*(*curr).next[0]).value = value;
                return false;
            }

            let node_height = SkipList::<K, V>::random_height();
            if node_height > self.height {
                for i in self.height..node_height {
                    update[i] = self.head;
                }
                self.height = node_height;
            }

            let new_node = Box::into_raw(Box::new(Node::new(key, value, node_height)));
            for i in 0..node_height {
                (*new_node).next[i] = (*update[i]).next[i];
                (*update[i]).next[i] = new_node;
            }
            self.len += 1;
        }
        true
    }

    pub fn get(&self, key: &K) -> Option<&V> {
        let mut curr = self.head;

        unsafe {
            for i in (0..self.height).rev() {
                while !(*curr).next[i].is_null()
                    && (*(*curr).next[i]).key < *key
                {
                    curr = (*curr).next[i];
                }
            }
            if !(*curr).next[0].is_null() && (*(*curr).next[0]).key == *key {
                Some(&(*(*curr).next[0]).value)
            } else {
                None
            }
        }
    }

    /// Remove the value for key. Returns true if existed.
    pub fn remove(&mut self, key: &K) -> bool {
        let mut update = vec![self.head; MAX_HEIGHT];
        let mut curr = self.head;
        let mut found = false;
        unsafe {
            for i in (0..self.height).rev() {
                while !(*curr).next[i].is_null()
                    && (*(*curr).next[i]).key < *key
                {
                    curr = (*curr).next[i];
                }
                update[i] = curr;
            }

            let next = (*curr).next[0];
            if !next.is_null() && (*next).key == *key {
                for i in 0..(*next).height() {
                    if (*update[i]).next[i] != next {
                        break;
                    }
                    (*update[i]).next[i] = (*next).next[i];
                }
                Box::from_raw(next); // free
                found = true;
                self.len -= 1;
                // Reduce height if necessary
                while self.height > 1 && (*self.head).next[self.height - 1].is_null() {
                    self.height -= 1;
                }
            }
        }
        found
    }

    pub fn len(&self) -> usize {
        self.len
    }

    pub fn is_empty(&self) -> bool {
        self.len == 0
    }
}

impl<K, V> Drop for SkipList<K, V> {
    fn drop(&mut self) {
        unsafe {
            let mut curr = (*self.head).next[0];
            while !curr.is_null() {
                let next = (*curr).next[0];
                Box::from_raw(curr);
                curr = next;
            }
            Box::from_raw(self.head);
        }
    }
}

