Certainly! Below is a **complete, working Rust implementation** for solving the **N-Queens problem**—specifically, finding all solutions and printing them. The solution uses **backtracking** and represents the board as a vector of column positions.

```rust
fn main() {
    let n = 8; // Change this to your desired N
    let solutions = solve_n_queens(n);

    println!("Total solutions for {}-Queens: {}", n, solutions.len());
    for solution in solutions {
        print_solution(&solution);
        println!();
    }
}

fn solve_n_queens(n: usize) -> Vec<Vec<usize>> {
    let mut results = Vec::new();
    let mut positions = Vec::new();
    backtrack(n, 0, &mut positions, &mut results);
    results
}

fn backtrack(n: usize, row: usize, positions: &mut Vec<usize>, results: &mut Vec<Vec<usize>>) {
    if row == n {
        results.push(positions.clone());
        return;
    }
    for col in 0..n {
        if is_safe(row, col, positions) {
            positions.push(col);
            backtrack(n, row + 1, positions, results);
            positions.pop();
        }
    }
}

fn is_safe(row: usize, col: usize, positions: &Vec<usize>) -> bool {
    for (r, &c) in positions.iter().enumerate() {
        if c == col || (c as isize - col as isize).abs() == (r as isize - row as isize).abs() {
            return false;
        }
    }
    true
}

fn print_solution(solution: &Vec<usize>) {
    let n = solution.len();
    for &col in solution {
        for c in 0..n {
            if c == col {
                print!("Q ");
            } else {
                print!(". ");
            }
        }
        println!();
    }
}
```

