use num_complex::Complex;
use rand::Rng;

pub struct Qubit {
    pub state: [Complex<f64>; 2],
}

impl Qubit {
    pub fn new() -> Self {
        Self { state: [Complex::new(1.0, 0.0), Complex::new(0.0, 0.0)] }
    }
    pub fn apply_h(&mut self) {
        let s0 = self.state[0];
        let s1 = self.state[1];
        self.state[0] = (s0 + s1) / Complex::new(2.0_f64.sqrt(), 0.0);
        self.state[1] = (s0 - s1) / Complex::new(2.0_f64.sqrt(), 0.0);
    }
    pub fn apply_x(&mut self) {
        self.state.swap(0, 1);
    }
    pub fn measure(&mut self) -> usize {
        let p0 = self.state[0].norm_sqr();
        let p = rand::thread_rng().gen::<f64>();
        let result = if p < p0 { 0 } else { 1 };
        self.state = if result == 0 {
            [Complex::new(1.0, 0.0), Complex::new(0.0, 0.0)]
        } else {
            [Complex::new(0.0, 0.0), Complex::new(1.0, 0.0)]
        };
        result
    }
}

fn main() {
    let mut q = Qubit::new();
    q.apply_h();
    let res = q.measure();
    println!("Result: {}", res);
}
