// Stack implementation in Rust

/// A generic stack data structure using Vec<T> internally.
#[derive(Debug)]
pub struct Stack<T> {
    items: Vec<T>,
}

impl<T> Stack<T> {
    /// Creates a new empty stack.
    pub fn new() -> Self {
        Self { items: Vec::new() }
    }

    /// Pushes an item onto the stack.
    pub fn push(&mut self, item: T) {
        self.items.push(item);
    }

    /// Pops the top item off the stack. Returns Some(item) or None if empty.
    pub fn pop(&mut self) -> Option<T> {
        self.items.pop()
    }

    /// Peeks at the top item without removing it. Returns Some(&item) or None if empty.
    pub fn peek(&self) -> Option<&T> {
        self.items.last()
    }

    /// Returns true if the stack is empty.
    pub fn is_empty(&self) -> bool {
        self.items.is_empty()
    }

    /// Returns the number of items in the stack.
    pub fn len(&self) -> usize {
        self.items.len()
    }
}

// Example usage
fn main() {
    let mut stack = Stack::new();

    println!("Is empty? {}", stack.is_empty());

    stack.push(10);
    stack.push(20);
    stack.push(30);

    println!("Stack after pushes: {:?}", stack);
    println!("Top element: {:?}", stack.peek());
    println!("Stack length: {}", stack.len());

    println!("Popped: {:?}", stack.pop());
    println!("Stack now: {:?}", stack);

    println!("Popped: {:?}", stack.pop());
    println!("Popped: {:?}", stack.pop());
    println!("Popped: {:?}", stack.pop()); // will be None, as stack is empty

    println!("Is empty? {}", stack.is_empty());
}
```

**How it works:**
- `Stack<T>` is generic, so you can use it with any type (integers, strings, etc.).
- Methods: `push`, `pop`, `peek`, `is_empty`, and `len`.
- The example in `main` demonstrates usage and prints out stack state.

