We’ll use the classic approach of:
- **Serialization:** Pre-order traversal, writing `"null"` for missing nodes.
- **Deserialization:** Rebuilding the tree from the serialized vector.

---

## Implementation

```rust
use std::rc::Rc;
use std::cell::RefCell;

// TreeNode definition
#[derive(Debug, PartialEq, Eq)]
pub struct TreeNode {
    pub val: i32,
    pub left: Option<Rc<RefCell<TreeNode>>>,
    pub right: Option<Rc<RefCell<TreeNode>>>,
}

impl TreeNode {
    pub fn new(val: i32) -> Rc<RefCell<TreeNode>> {
        Rc::new(RefCell::new(TreeNode { val, left: None, right: None }))
    }
}

// Serialize function: Convert tree to a string
fn serialize(root: Option<Rc<RefCell<TreeNode>>>) -> String {
    fn helper(node: Option<Rc<RefCell<TreeNode>>>, output: &mut Vec<String>) {
        if let Some(node) = node {
            let node = node.borrow();
            output.push(node.val.to_string());
            helper(node.left.clone(), output);
            helper(node.right.clone(), output);
        } else {
            output.push("null".to_string());
        }
    }
    let mut output = Vec::new();
    helper(root, &mut output);
    output.join(",")
}

// Deserialize function: Convert a string back to the tree
fn deserialize(data: &str) -> Option<Rc<RefCell<TreeNode>>> {
    fn helper(vals: &mut std::slice::Iter<&str>) -> Option<Rc<RefCell<TreeNode>>> {
        if let Some(&s) = vals.next() {
            if s == "null" {
                None
            } else {
                let val = s.parse::<i32>().unwrap();
                let node = TreeNode::new(val);
                node.borrow_mut().left = helper(vals);
                node.borrow_mut().right = helper(vals);
                Some(node)
            }
        } else {
            None
        }
    }
    let vals: Vec<&str> = data.split(',').collect();
    helper(&mut vals.iter())
}

// Test
fn main() {
    // Example: Build a small tree
    //       1
    //      / \
    //     2   3
    //        / \
    //       4   5
    let root = TreeNode::new(1);
    root.borrow_mut().left = Some(TreeNode::new(2));
    let right = TreeNode::new(3);
    right.borrow_mut().left = Some(TreeNode::new(4));
    right.borrow_mut().right = Some(TreeNode::new(5));
    root.borrow_mut().right = Some(right);

    let serialized = serialize(Some(root.clone()));
    println!("Serialized: {}", serialized);

    let deserialized = deserialize(&serialized);

    // Check equality
    fn equal(a: Option<Rc<RefCell<TreeNode>>>, b: Option<Rc<RefCell<TreeNode>>>) -> bool {
        match (a, b) {
            (None, None) => true,
            (Some(a), Some(b)) => {
                let a = a.borrow();
                let b = b.borrow();
                a.val == b.val &&
                    equal(a.left.clone(), b.left.clone()) &&
                    equal(a.right.clone(), b.right.clone())
            }
            _ => false,
        }
    }
    assert!(equal(Some(root), deserialized));
    println!("Test passed!");
}
```

---

## How it works

- **Serialization:** `serialize()` traverses the tree in pre-order and outputs each value or `"null"` for absent nodes, joined by commas.
- **Deserialization:** `deserialize()` rebuilds the tree recursively from the comma-separated representation.

