## `TokenBucket` Struct

```rust
use std::sync::{Arc, Mutex};
use std::time::{Duration, Instant};
use std::thread;

/// Token Bucket struct
pub struct TokenBucket {
    capacity: u32,         // Max tokens
    tokens: u32,           // Current tokens
    refill_rate: u32,      // Tokens to add per interval
    interval: Duration,    // Interval for refilling tokens
    last_refill: Instant,  // Last refill time
}

impl TokenBucket {
    /// Create a new TokenBucket
    pub fn new(capacity: u32, refill_rate: u32, interval: Duration) -> Self {
        Self {
            capacity,
            tokens: capacity,
            refill_rate,
            interval,
            last_refill: Instant::now(),
        }
    }

    /// Try to take `n` tokens from the bucket. Returns true if successful.
    pub fn try_take(&mut self, n: u32) -> bool {
        self.refill();
        if self.tokens >= n {
            self.tokens -= n;
            true
        } else {
            false
        }
    }

    /// Refill tokens based on the interval and refill_rate
    fn refill(&mut self) {
        let now = Instant::now();
        let elapsed = now.duration_since(self.last_refill);

        if elapsed >= self.interval {
            let intervals = elapsed.as_secs_f64() / self.interval.as_secs_f64();
            let added_tokens = (intervals * self.refill_rate as f64).floor() as u32;
            if added_tokens > 0 {
                self.tokens = (self.tokens + added_tokens).min(self.capacity);
                self.last_refill = now;
            }
        }
    }
}

/// Arc/Mutex wrapper for thread safety
pub type SharedTokenBucket = Arc<Mutex<TokenBucket>>;
```

---

## Usage Example

```rust
fn main() {
    // 5 tokens per second, max 10 tokens.
    let bucket = Arc::new(Mutex::new(TokenBucket::new(
        10,
        5,
        Duration::from_secs(1),
    )));

    let mut handles = vec![];

    // Launch 10 threads to try to take tokens every 200ms
    for i in 0..10 {
        let bucket = bucket.clone();
        let handle = thread::spawn(move || {
            for j in 0..5 {
                thread::sleep(Duration::from_millis(200));
                let mut token_bucket = bucket.lock().unwrap();
                if token_bucket.try_take(1) {
                    println!("Thread {} got a token at iteration {}", i, j);
                } else {
                    println!("Thread {} denied at iteration {}", i, j);
                }
            }
        });
        handles.push(handle);
    }

    // Wait for threads to finish
    for handle in handles {
        handle.join().unwrap();
    }
}
```

