Certainly! Below is a complete, working implementation of a **bounded blocking queue** in Rust.

This queue:

- Has a fixed maximum capacity.
- Supports concurrent access (`push()` and `pop()`) from multiple threads.
- Blocks on `push()` if the queue is full, until space is available.
- Blocks on `pop()` if the queue is empty, until an item becomes available.

We’ll use `Arc<Mutex<_>>` plus `Condvar` for synchronization. This is a classic pattern in Rust for building concurrent data structures.

---

```rust
use std::collections::VecDeque;
use std::sync::{Arc, Mutex, Condvar};
use std::time::Duration;

pub struct BoundedBlockingQueue<T> {
    inner: Arc<Inner<T>>,
}

struct Inner<T> {
    queue: Mutex<VecDeque<T>>,
    not_empty: Condvar,
    not_full: Condvar,
    capacity: usize,
}

impl<T> BoundedBlockingQueue<T> {
    pub fn new(capacity: usize) -> Self {
        assert!(capacity > 0, "capacity must be non-zero");
        Self {
            inner: Arc::new(Inner {
                queue: Mutex::new(VecDeque::with_capacity(capacity)),
                not_empty: Condvar::new(),
                not_full: Condvar::new(),
                capacity,
            }),
        }
    }

    pub fn push(&self, item: T) {
        let mut queue = self.inner.queue.lock().unwrap();
        while queue.len() == self.inner.capacity {
            queue = self.inner.not_full.wait(queue).unwrap();
        }
        queue.push_back(item);
        // Notify waiting consumers (pop())
        self.inner.not_empty.notify_one();
    }

    pub fn pop(&self) -> T {
        let mut queue = self.inner.queue.lock().unwrap();
        while queue.is_empty() {
            queue = self.inner.not_empty.wait(queue).unwrap();
        }
        let item = queue.pop_front().unwrap();
        // Notify waiting producers (push())
        self.inner.not_full.notify_one();
        item
    }

    /// Try to push an item, waiting for at most `timeout`.
    /// Returns Ok(()) if successful, Err(item) if timed out.
    pub fn push_timeout(&self, item: T, timeout: Duration) -> Result<(), T> {
        let mut queue = self.inner.queue.lock().unwrap();
        let mut remaining = timeout;
        while queue.len() == self.inner.capacity {
            let (new_queue, wait_result) = self.inner.not_full.wait_timeout(queue, remaining).unwrap();
            queue = new_queue;
            if wait_result.timed_out() {
                return Err(item);
            }
            // decrease remaining time
            remaining = match remaining.checked_sub(wait_result.elapsed()) {
                Some(r) => r,
                None => Duration::from_secs(0),
            };
        }
        queue.push_back(item);
        self.inner.not_empty.notify_one();
        Ok(())
    }

    /// Try to pop an item, waiting for at most `timeout`.
    /// Returns Ok(item) if successful, Err(()) if timed out.
    pub fn pop_timeout(&self, timeout: Duration) -> Result<T, ()> {
        let mut queue = self.inner.queue.lock().unwrap();
        let mut remaining = timeout;
        while queue.is_empty() {
            let (new_queue, wait_result) = self.inner.not_empty.wait_timeout(queue, remaining).unwrap();
            queue = new_queue;
            if wait_result.timed_out() {
                return Err(());
            }
            remaining = match remaining.checked_sub(wait_result.elapsed()) {
                Some(r) => r,
                None => Duration::from_secs(0),
            };
        }
        let item = queue.pop_front().unwrap();
        self.inner.not_full.notify_one();
        Ok(item)
    }
}

// Clone makes BoundedBlockingQueue usable from multiple threads.
impl<T> Clone for BoundedBlockingQueue<T> {
    fn clone(&self) -> Self {
        BoundedBlockingQueue { inner: Arc::clone(&self.inner) }
    }
}

// Example usage with threads:
fn main() {
    use std::thread;
    let queue = BoundedBlockingQueue::new(2);

    let producer = {
        let q = queue.clone();
        thread::spawn(move || {
            for i in 0..5 {
                println!("Producer pushing {}", i);
                q.push(i);
                println!("Producer pushed {}", i);
            }
        })
    };

    let consumer = {
        let q = queue.clone();
        thread::spawn(move || {
            for _ in 0..5 {
                let val = q.pop();
                println!("Consumer got {}", val);
            }
        })
    };

    producer.join().unwrap();
    consumer.join().unwrap();
}
```

---

**Features:**

- **thread-safe, blocking push/pop**
- **bounded** (fixed size)
- **timeout versions:** `push_timeout`, `pop_timeout`
- **easy to clone**, so multiple threads can use the same queue.

**How it works:**
- If you try to `push` when full, it waits for space.
- If you try to `pop` when empty, it waits for data.
- Notifies appropriately to wake up threads.

