Certainly! Here’s a simple arithmetic expression evaluator in Rust supporting `+`, `-`, `*`, `/` and parentheses. It uses recursive descent parsing for operator precedence.

### Complete, Working Rust Code

```rust
use std::iter::Peekable;
use std::str::Chars;

// Token types
#[derive(Debug, Clone, PartialEq)]
enum Token {
    Number(f64),
    Plus,
    Minus,
    Mul,
    Div,
    LParen,
    RParen,
}

// Tokenize input string
fn tokenize(input: &str) -> Result<Vec<Token>, String> {
    let mut tokens = Vec::new();
    let mut chars = input.chars().peekable();

    while let Some(&ch) = chars.peek() {
        match ch {
            ' ' | '\t' => { chars.next(); }
            '+' => { tokens.push(Token::Plus); chars.next(); }
            '-' => { tokens.push(Token::Minus); chars.next(); }
            '*' => { tokens.push(Token::Mul); chars.next(); }
            '/' => { tokens.push(Token::Div); chars.next(); }
            '(' => { tokens.push(Token::LParen); chars.next(); }
            ')' => { tokens.push(Token::RParen); chars.next(); }
            '0'..='9' | '.' => {
                // Parse number (integer or float)
                let mut num = String::new();
                while let Some(&c) = chars.peek() {
                    if c.is_ascii_digit() || c == '.' {
                        num.push(c);
                        chars.next();
                    } else {
                        break;
                    }
                }
                match num.parse::<f64>() {
                    Ok(n) => tokens.push(Token::Number(n)),
                    Err(_) => return Err(format!("Failed to parse number: {}", num)),
                }
            }
            _ => return Err(format!("Unknown character: {}", ch)),
        }
    }
    Ok(tokens)
}

// Parser/evaluator
struct Parser<'a> {
    tokens: &'a [Token],
    pos: usize,
}

impl<'a> Parser<'a> {
    fn new(tokens: &'a [Token]) -> Self {
        Parser { tokens, pos: 0 }
    }

    fn peek(&self) -> Option<&Token> {
        self.tokens.get(self.pos)
    }

    fn next(&mut self) -> Option<&Token> {
        let tok = self.tokens.get(self.pos);
        if tok.is_some() {
            self.pos += 1;
        }
        tok
    }

    // expr = term ((+|-) term)*
    fn parse_expr(&mut self) -> Result<f64, String> {
        let mut value = self.parse_term()?;

        loop {
            match self.peek() {
                Some(Token::Plus) => {
                    self.next();
                    value += self.parse_term()?;
                }
                Some(Token::Minus) => {
                    self.next();
                    value -= self.parse_term()?;
                }
                _ => break,
            }
        }
        Ok(value)
    }

    // term = factor ((*|/) factor)*
    fn parse_term(&mut self) -> Result<f64, String> {
        let mut value = self.parse_factor()?;

        loop {
            match self.peek() {
                Some(Token::Mul) => {
                    self.next();
                    value *= self.parse_factor()?;
                }
                Some(Token::Div) => {
                    self.next();
                    let divisor = self.parse_factor()?;
                    if divisor == 0.0 {
                        return Err("Division by zero".to_string());
                    }
                    value /= divisor;
                }
                _ => break,
            }
        }
        Ok(value)
    }

    // factor = NUMBER | '(' expr ')' | unary
    fn parse_factor(&mut self) -> Result<f64, String> {
        match self.peek() {
            Some(Token::Number(n)) => {
                self.next();
                Ok(*n)
            }
            Some(Token::LParen) => {
                self.next();
                let val = self.parse_expr()?;
                match self.next() {
                    Some(Token::RParen) => Ok(val),
                    _ => Err("Expected ')'".to_string()),
                }
            }
            Some(Token::Minus) => {
                self.next();
                Ok(-self.parse_factor()?)
            }
            Some(Token::Plus) => {
                self.next();
                self.parse_factor()
            }
            _ => Err("Unexpected token".to_string()),
        }
    }
}

// Main eval function
fn eval(expr: &str) -> Result<f64, String> {
    let tokens = tokenize(expr)?;
    let mut parser = Parser::new(&tokens);
    let result = parser.parse_expr()?;
    if parser.peek().is_some() {
        Err("Unexpected extra tokens".to_string())
    } else {
        Ok(result)
    }
}

// Example usage
fn main() {
    let examples = [
        "1 + 2 * 3",           // 7
        "(1 + 2) * 3",         // 9
        "10 / (2 + 3)",        // 2
        "-4 + 5 * 6",          // 26
        "3.5 * 2 - 1",         // 6
        "2 / 0",               // Division by zero error
        "1 + (2",              // Syntax error
    ];

    for expr in &examples {
        print!("{expr} = ");
        match eval(expr) {
            Ok(val) => println!("{val}"),
            Err(err) => println!("Error: {err}"),
        }
    }
}
```

---

**How it works:**
- **Tokenization:** Converts input string into tokens (numbers, operators, parentheses).
- **Parsing/Analyzing:** Recursive descent parsing for correct precedence (`*`, `/` > `+`, `-`), parentheses, unary negation.
- **Evaluation:** Computes the result as it parses.
- **Error Handling:** Handles invalid input, division by zero, unmatched parentheses.

**To run it:**  
Save as `main.rs` and run with `cargo run` or `rustc main.rs && ./main`.

