```rust
// Simple regex matcher supporting ., *
use std::env;

fn is_match(s: &str, p: &str) -> bool {
    let s_chars: Vec<char> = s.chars().collect();
    let p_chars: Vec<char> = p.chars().collect();

    fn dp(i: usize, j: usize, s: &[char], p: &[char], memo: &mut Vec<Vec<Option<bool>>>) -> bool {
        if let Some(res) = memo[i][j] {
            return res;
        }
        let ans = if j == p.len() {
            i == s.len()
        } else {
            let first_match = i < s.len() &&
                (p[j] == s[i] || p[j] == '.');
            if j + 1 < p.len() && p[j+1] == '*' {
                dp(i, j+2, s, p, memo) || (first_match && dp(i+1, j, s, p, memo))
            } else {
                first_match && dp(i+1, j+1, s, p, memo)
            }
        };
        memo[i][j] = Some(ans);
        ans
    }

    let mut memo = vec![vec![None; p_chars.len()+1]; s_chars.len()+1];
    dp(0, 0, &s_chars, &p_chars, &mut memo)
}

fn main() {
    // Accept two arguments: string and pattern.
    let args: Vec<String> = env::args().collect();
    if args.len() < 3 {
        println!("Usage: {} <string> <pattern>", args[0]);
        println!("Example: {} abcd .*", args[0]);
        println!("Example: {} aa a*", args[0]);
        return;
    }

    let s = &args[1];
    let p = &args[2];

    println!("String: {}", s);
    println!("Pattern: {}", p);
    let matched = is_match(s, p);

    println!("Matched: {}", matched);
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_examples() {
        assert_eq!(is_match("aa", "a"), false);
        assert_eq!(is_match("aa", "a*"), true);
        assert_eq!(is_match("ab", ".*"), true);
        assert_eq!(is_match("aab", "c*a*b"), true);
        assert_eq!(is_match("mississippi", "mis*is*p*."), false);
        assert_eq!(is_match("", ".*"), true);
        assert_eq!(is_match("abc", "a.*c"), true);
    }
}
```

