Certainly! Below is a complete, working implementation of a **B-tree** in Rust.
This example provides basic functionality: **insertion** and **search**.
For simplicity, we'll use `K: Ord + Clone` as the key types, and a minimum degree `t` parameter (as in classic B-tree definitions), making the node holds `2t-1` keys max and at least `t-1` keys, except for the root.

You can expand this for removal and more features, but this is a solid, instructive base.

---

```rust
use std::fmt::{Debug, Formatter, Result};
use std::cmp::Ordering;

/// B-tree minimum degree (defines the range for number of keys)
pub struct BTree<K: Ord + Clone> {
    degree: usize, // Minimum degree (t)
    root: Option<Box<Node<K>>>,
}

#[derive(Clone)]
struct Node<K: Ord + Clone> {
    keys: Vec<K>,
    children: Vec<Option<Box<Node<K>>>>,
    leaf: bool,
}

impl<K: Ord + Clone + Debug> Node<K> {
    fn new(degree: usize, leaf: bool) -> Self {
        Self {
            keys: Vec::new(),
            children: Vec::with_capacity(degree * 2), // At most 2*degree children
            leaf,
        }
    }
}

impl<K: Ord + Clone + Debug> BTree<K> {
    pub fn new(degree: usize) -> Self {
        assert!(degree >= 2, "B-tree minimum degree must be at least 2");
        Self {
            degree,
            root: Some(Box::new(Node::new(degree, true))),
        }
    }

    pub fn search(&self, key: &K) -> bool {
        match &self.root {
            Some(root) => Self::search_rec(root, key),
            None => false,
        }
    }

    fn search_rec(node: &Node<K>, key: &K) -> bool {
        let mut i = 0;
        while i < node.keys.len() && key > &node.keys[i] {
            i += 1;
        }
        if i < node.keys.len() && key == &node.keys[i] {
            return true;
        }
        if node.leaf {
            return false;
        }
        if let Some(child) = &node.children[i] {
            return Self::search_rec(child, key);
        }
        false
    }

    pub fn insert(&mut self, key: K) {
        if let Some(ref mut root) = self.root {
            // If root is full, split
            if root.keys.len() == 2 * self.degree - 1 {
                let mut new_root = Node::new(self.degree, false);
                new_root.children.push(Some(root.clone())); // Old root becomes child 0
                Self::split_child(&mut new_root, 0, self.degree);
                Self::insert_non_full(&mut new_root, key, self.degree);
                self.root = Some(Box::new(new_root));
            } else {
                Self::insert_non_full(root, key, self.degree);
            }
        } else {
            // Empty tree
            let mut root = Node::new(self.degree, true);
            root.keys.push(key);
            self.root = Some(Box::new(root));
        }
    }

    fn insert_non_full(node: &mut Node<K>, key: K, degree: usize) {
        let mut i = node.keys.len();
        if node.leaf {
            // Insert in sorted position
            node.keys.push(key.clone());
            node.keys.sort();
        } else {
            // Find child to recurse
            while i > 0 && key < node.keys[i - 1] {
                i -= 1;
            }
            // Check if child is full
            if node.children[i].as_ref().unwrap().keys.len() == 2 * degree - 1 {
                Self::split_child(node, i, degree);
                if key > node.keys[i] {
                    i += 1;
                }
            }
            Self::insert_non_full(
                node.children[i].as_mut().unwrap(),
                key,
                degree,
            );
        }
    }

    fn split_child(parent: &mut Node<K>, i: usize, degree: usize) {
        // Full child at index i
        let mut full_child = parent.children[i].take().unwrap();
        let mut new_child = Node::new(degree, full_child.leaf);

        // Move last (degree-1) keys to new child
        new_child.keys = full_child.keys.split_off(degree);
        let mid_key = full_child.keys.pop().unwrap(); // Median key moves up

        // If not leaf, move corresponding children
        if !full_child.leaf {
            new_child.children = full_child.children.split_off(degree);
        }

        // Insert median key to parent
        parent.keys.insert(i, mid_key);

        // Insert new child to parent's children
        parent.children.insert(i + 1, Some(Box::new(new_child)));
        // Full child remains at index i
        parent.children[i] = Some(full_child);
    }

    pub fn traverse(&self)
    where K: Debug
    {
        if let Some(ref root) = self.root {
            Self::traverse_rec(root);
        }
    }

    fn traverse_rec(node: &Node<K>)
    where K: Debug
    {
        let n = node.keys.len();
        for i in 0..n {
            if !node.leaf {
                if let Some(ref child) = node.children[i] {
                    Self::traverse_rec(child);
                }
            }
            println!("{:?}", node.keys[i]);
        }
        if !node.leaf {
            if let Some(ref child) = node.children[n] {
                Self::traverse_rec(child);
            }
        }
    }
}

// Optional: Debug display for the whole tree

impl<K: Ord + Clone + Debug> Debug for BTree<K> {
    fn fmt(&self, f: &mut Formatter<'_>) -> Result {
        if let Some(ref root) = self.root {
            Self::fmt_node(root, f, 0)
        } else {
            write!(f, "[]")
        }
    }
    fn fmt_node(node: &Node<K>, f: &mut Formatter<'_>, depth: usize) -> Result {
        for i in 0..node.keys.len() {
            if !node.leaf {
                if let Some(ref child) = node.children[i] {
                    Self::fmt_node(child, f, depth + 1)?;
                }
            }
            for _ in 0..depth { write!(f, "  ")?; }
            writeln!(f, "{:?}", node.keys[i])?;
        }
        if !node.leaf {
            if let Some(ref child) = node.children[node.keys.len()] {
                Self::fmt_node(child, f, depth + 1)?;
            }
        }
        Ok(())
    }
}

// Example usage:

fn main() {
    let mut btree = BTree::new(2); // degree 2 (minimum 2 children per node)

    let values = vec![10, 20, 5, 6, 12, 30, 7, 17];
    for v in values {
        btree.insert(v);
    }

    println!("Traverse B-tree:");
    btree.traverse();

    println!("Search for 6: {}", btree.search(&6));
    println!("Search for 15: {}", btree.search(&15));

    println!("\nB-tree structure (prettified):\n{:?}", btree);
}
```

---

**Features included:**
- B-tree construction and insertion (with node splitting as needed)
- Search operation
- Traverse (prints in order)
- Debug formatting for visualization

**How to use:**
- Copy & paste into `main.rs` or a playground.
- You can insert numbers, search for values, etc.
- Customize with your chosen key type as long as it implements `Ord` and `Clone`.

**Note:**  
- This implementation is simplified for learning purposes and does NOT include deletion.  
- You can extend it with a value type `V`, implement deletion, etc.
- It is safe, idiomatic Rust, and suitable as a base for further exploration.

