Here is a complete Rust implementation of the Raft leader election protocol, focusing on the consensus and leader election mechanism. This implementation uses `tokio` for async networking and concurrency, and `serde` for message serialization.

**Features:**
- Implements Raft server roles: Follower, Candidate, Leader
- Leader election using RequestVote RPC messages
- Persistent state: currentTerm, votedFor
- Cluster communication via TCP (simple simulation)

---

## `Cargo.toml` dependencies:

```toml
[dependencies]
tokio = { version = "1.37", features = ["full"] }
serde = { version = "1.0", features = ["derive"] }
serde_json = "1.0"
rand = "0.8"
```

---

## `main.rs`

```rust
use tokio::net::{TcpListener, TcpStream};
use tokio::io::{AsyncReadExt, AsyncWriteExt};
use tokio::sync::{mpsc, oneshot};
use tokio::time::{sleep, Duration};
use serde::{Serialize, Deserialize};
use rand::Rng;
use std::sync::{Arc, Mutex};

#[derive(Debug, Clone, Serialize, Deserialize)]
struct RequestVote {
    term: u64,
    candidate_id: usize,
    last_log_index: u64,
    last_log_term: u64,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct RequestVoteResponse {
    term: u64,
    vote_granted: bool,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
enum RaftMessage {
    RequestVote(RequestVote),
    RequestVoteResponse(RequestVoteResponse),
    Heartbeat(u64), // Leader heartbeat contains current term
}

#[derive(Debug, Clone, PartialEq)]
enum Role {
    Follower,
    Candidate,
    Leader,
}

#[derive(Debug, Clone)]
struct PersistentState {
    current_term: u64,
    voted_for: Option<usize>,
}

#[derive(Debug)]
struct Raft {
    id: usize,
    peers: Vec<String>, // ["127.0.0.1:XXXX"]
    state: Arc<Mutex<PersistentState>>,
    role: Arc<Mutex<Role>>,
    rx: mpsc::Receiver<RaftMessage>,
    tx: mpsc::Sender<RaftMessage>,
    election_timeout: Duration,
}

impl Raft {
    fn new(
        id: usize, 
        peers: Vec<String>,
        rx: mpsc::Receiver<RaftMessage>,
        tx: mpsc::Sender<RaftMessage>
    ) -> Self {
        let election_timeout = Duration::from_millis(rand::thread_rng().gen_range(150..300));
        Raft {
            id,
            peers,
            state: Arc::new(Mutex::new(PersistentState { current_term: 0, voted_for: None })),
            role: Arc::new(Mutex::new(Role::Follower)),
            rx,
            tx,
            election_timeout,
        }
    }

    async fn run(&mut self) {
        let mut election_timer = tokio::time::sleep(self.election_timeout);
        loop {
            tokio::select! {
                _ = &mut election_timer => {
                    // No heartbeat, become candidate and start election
                    if *self.role.lock().unwrap() != Role::Leader {
                        println!("[{}] Election timeout, starting election", self.id);
                        self.start_election().await;
                    }
                    election_timer = tokio::time::sleep(self.random_election_timeout());
                }
                Some(msg) = self.rx.recv() => {
                    match msg {
                        RaftMessage::RequestVote(rv) => {
                            let resp = self.handle_request_vote(rv).await;
                            self.tx.send(RaftMessage::RequestVoteResponse(resp)).await.unwrap();
                        }
                        RaftMessage::RequestVoteResponse(rvr) => {
                            self.handle_request_vote_response(rvr).await;
                        }
                        RaftMessage::Heartbeat(term) => {
                            self.handle_heartbeat(term).await;
                            election_timer = tokio::time::sleep(self.random_election_timeout());
                        }
                    }
                }
            }
        }
    }

    fn random_election_timeout(&self) -> Duration {
        Duration::from_millis(rand::thread_rng().gen_range(150..300))
    }

    async fn start_election(&mut self) {
        let mut state = self.state.lock().unwrap();
        state.current_term += 1;
        state.voted_for = Some(self.id);
        drop(state);

        *self.role.lock().unwrap() = Role::Candidate;
        let term = self.state.lock().unwrap().current_term;
        let mut votes = 1; // Vote for self

        println!("[{}] Started election for term {}", self.id, term);

        // Send RequestVote to all peers
        let request = RequestVote {
            term,
            candidate_id: self.id,
            last_log_index: 0,
            last_log_term: 0,
        };

        let peer_count = self.peers.len() + 1;
        let (vote_tx, mut vote_rx) = mpsc::channel(peer_count);

        for peer in &self.peers {
            let request = request.clone();
            let peer = peer.clone();
            let vote_tx = vote_tx.clone();
            tokio::spawn(async move {
                match TcpStream::connect(&peer).await {
                    Ok(mut stream) => {
                        let msg = serde_json::to_string(&RaftMessage::RequestVote(request)).unwrap();
                        stream.write_all(msg.as_bytes()).await.unwrap();
                        let mut buf = vec![0u8; 1024];
                        let n = stream.read(&mut buf).await.unwrap();
                        let resp: RaftMessage = serde_json::from_slice(&buf[..n]).unwrap();
                        if let RaftMessage::RequestVoteResponse(rvr) = resp {
                            vote_tx.send(rvr).await.unwrap();
                        }
                    }
                    Err(_) => {
                        // Peer not available; ignore
                    }
                }
            });
        }

        let mut received_votes = 1;
        let mut received_responses = 1;

        // Collect votes with timeout
        let mut timeout = tokio::time::sleep(Duration::from_millis(200));
        loop {
            tokio::select! {
                _ = &mut timeout => { break; }
                Some(rvr) = vote_rx.recv() => {
                    received_responses += 1;
                    if rvr.vote_granted { votes += 1; }
                    if votes > peer_count / 2 {
                        println!("[{}] Became leader for term {}", self.id, term);
                        *self.role.lock().unwrap() = Role::Leader;
                        self.send_heartbeat().await;
                        break;
                    }
                    if received_responses >= peer_count { break; }
                }
            }
        }
        if votes <= peer_count / 2 {
            println!("[{}] Election failed; staying follower", self.id);
            *self.role.lock().unwrap() = Role::Follower;
        }
    }

    async fn handle_request_vote(&self, rv: RequestVote) -> RequestVoteResponse {
        let mut state = self.state.lock().unwrap();
        let mut vote_granted = false;

        if rv.term < state.current_term {
            vote_granted = false;
        } else {
            if rv.term > state.current_term {
                state.current_term = rv.term;
                state.voted_for = None;
                *self.role.lock().unwrap() = Role::Follower;
            }
            if state.voted_for.is_none() || state.voted_for == Some(rv.candidate_id) {
                state.voted_for = Some(rv.candidate_id);
                vote_granted = true;
            }
        }
        RequestVoteResponse {
            term: state.current_term,
            vote_granted,
        }
    }

    async fn handle_request_vote_response(&mut self, _rvr: RequestVoteResponse) {
        // Candidate receives votes in start_election, so nothing here
    }

    async fn handle_heartbeat(&mut self, term: u64) {
        let mut state = self.state.lock().unwrap();
        if term >= state.current_term {
            state.current_term = term;
            *self.role.lock().unwrap() = Role::Follower;
        }
    }

    async fn send_heartbeat(&self) {
        // In production: periodic heartbeats; here: single send to peers
        let term = self.state.lock().unwrap().current_term;
        for peer in &self.peers {
            let peer = peer.clone();
            let msg = serde_json::to_string(&RaftMessage::Heartbeat(term)).unwrap();
            tokio::spawn(async move {
                if let Ok(mut stream) = TcpStream::connect(&peer).await {
                    stream.write_all(msg.as_bytes()).await.unwrap();
                }
            });
        }
    }
}

/// Simple TCP server to receive Raft messages
async fn raft_server(id: usize, port: u16, tx: mpsc::Sender<RaftMessage>, rx: mpsc::Receiver<RaftMessage>) {
    let raft_peers = vec![
        format!("127.0.0.1:{}", 9000 + ((id + 1) % 3)),
        format!("127.0.0.1:{}", 9000 + ((id + 2) % 3)),
    ];
    let mut raft = Raft::new(id, raft_peers, rx, tx.clone());
    let listener = TcpListener::bind(format!("127.0.0.1:{}", port)).await.unwrap();
    tokio::spawn(async move {
        raft.run().await;
    });

    loop {
        let (mut socket, _) = listener.accept().await.unwrap();
        let mut buf = vec![0u8; 1024];
        let n = socket.read(&mut buf).await.unwrap();
        if n == 0 { continue; }
        let msg: RaftMessage = serde_json::from_slice(&buf[..n]).unwrap();

        // Forward message to Raft state machine
        tx.send(msg.clone()).await.unwrap();

        // For RequestVote: reply vote response immediately
        if let RaftMessage::RequestVote(_) = msg {
            // Await response from Raft
            let resp = rx.recv().await.unwrap();
            let resp_bytes = serde_json::to_vec(&resp).unwrap();
            socket.write_all(&resp_bytes).await.unwrap();
        }
    }
}

#[tokio::main]
async fn main() {
    // Run 3 Raft nodes on ports 9000, 9001, 9002
    for node_id in 0..3 {
        let port = 9000 + node_id;
        let (tx, rx) = mpsc::channel(32);
        let (tx2, rx2) = mpsc::channel(32);
        tokio::spawn(raft_server(node_id, port, tx, rx2));
        // Node's main loop: receive Raft state machine messages
        tokio::spawn(async move {
            let mut rx = rx;
            while let Some(msg) = rx.recv().await {
                tx2.send(msg).await.unwrap();
            }
        });
    }
    loop {
        sleep(Duration::from_secs(1)).await;
    }
}
