Certainly! Here is a fully **persistent (immutable) red-black tree** implementation in Rust. The API allows insertion (with structure sharing), lookup, and basic iteration. Keys must implement `Ord` and values can be any type. The tree is immutable: insertions return a new tree, and old versions stay unchanged.

---

### Rust Implementation: Persistent Red-Black Tree

```rust
use std::cmp::Ordering;
use std::rc::Rc;

/// Color of a node in the red-black tree.
#[derive(Clone, Copy, PartialEq, Eq, Debug)]
enum Color {
    Red,
    Black,
}

/// Node structure (Rc for persistence).
#[derive(Clone)]
struct Node<K, V> {
    color: Color,
    key: K,
    value: V,
    left: Option<Rc<Node<K, V>>>,
    right: Option<Rc<Node<K, V>>>,
}

/// Persistent Red-Black Tree.
#[derive(Clone)]
pub struct RBTree<K, V> {
    root: Option<Rc<Node<K, V>>>,
}

impl<K: Ord, V> RBTree<K, V> {
    /// Creates a new empty tree.
    pub fn new() -> Self {
        RBTree { root: None }
    }

    /// Lookup value for a key.
    pub fn get(&self, key: &K) -> Option<&V> {
        let mut node = self.root.as_ref();
        while let Some(n) = node {
            match key.cmp(&n.key) {
                Ordering::Less => node = n.left.as_ref(),
                Ordering::Greater => node = n.right.as_ref(),
                Ordering::Equal => return Some(&n.value),
            }
        }
        None
    }

    /// Insert a key-value pair, returning a new tree.
    pub fn insert(&self, key: K, value: V) -> Self {
        let root = Self::insert_rec(&self.root, key, value);
        RBTree {
            root: root.map(|n| Self::set_color(n, Color::Black)),
        }
    }

    fn insert_rec(
        node: &Option<Rc<Node<K, V>>>,
        key: K,
        value: V,
    ) -> Option<Rc<Node<K, V>>> {
        match node {
            None => {
                // New nodes are always Red
                Some(Rc::new(Node {
                    color: Color::Red,
                    key,
                    value,
                    left: None,
                    right: None,
                }))
            }
            Some(n) => {
                match key.cmp(&n.key) {
                    Ordering::Less => {
                        let left = Self::insert_rec(&n.left, key, value);
                        Self::balance_right(Rc::new(Node {
                            color: n.color,
                            key: n.key.clone(),
                            value: n.value.clone(),
                            left,
                            right: n.right.clone(),
                        }))
                    }
                    Ordering::Greater => {
                        let right = Self::insert_rec(&n.right, key, value);
                        Self::balance_right(Rc::new(Node {
                            color: n.color,
                            key: n.key.clone(),
                            value: n.value.clone(),
                            left: n.left.clone(),
                            right,
                        }))
                    }
                    Ordering::Equal => {
                        // Overwrite value
                        Some(Rc::new(Node {
                            color: n.color,
                            key: n.key.clone(),
                            value,
                            left: n.left.clone(),
                            right: n.right.clone(),
                        }))
                    }
                }
            }
        }
    }

    /// Ensure proper balancing after insertion.
    /// Insert is always performed "down" the tree, so we can perform balancing as we return up.
    fn balance_right(node: Rc<Node<K, V>>) -> Option<Rc<Node<K, V>>> {
        // Handle only simple cases (left leaning red-black tree)
        let n = &*node;
        let (left_is_red, right_is_red) =
            (Self::is_red(&n.left), Self::is_red(&n.right));

        let mut node = node;

        // Rotate left if right is red and left is not red
        if right_is_red && !left_is_red {
            node = Self::rotate_left(node);
        }
        // Rotate right if left is red and left's left is red
        let n = &*node;
        if Self::is_red(&n.left)
            && Self::is_red(&n.left.as_ref().unwrap().left)
        {
            node = Self::rotate_right(node);
        }
        // Flip colors if both left and right are red
        let n = &*node;
        if Self::is_red(&n.left) && Self::is_red(&n.right) {
            node = Self::flip_colors(node);
        }
        Some(node)
    }

    fn is_red(node: &Option<Rc<Node<K, V>>>) -> bool {
        node.as_ref().map_or(false, |n| n.color == Color::Red)
    }

    /// Rotate left: makes right child the parent.
    fn rotate_left(node: Rc<Node<K, V>>) -> Rc<Node<K, V>> {
        let mut n = &*node;
        let right = n.right.as_ref().unwrap();

        Rc::new(Node {
            color: n.color,
            key: right.key.clone(),
            value: right.value.clone(),
            left: Some(Rc::new(Node {
                color: Color::Red,
                key: n.key.clone(),
                value: n.value.clone(),
                left: n.left.clone(),
                right: right.left.clone(),
            })),
            right: right.right.clone(),
        })
    }

    /// Rotate right: makes left child the parent.
    fn rotate_right(node: Rc<Node<K, V>>) -> Rc<Node<K, V>> {
        let n = &*node;
        let left = n.left.as_ref().unwrap();

        Rc::new(Node {
            color: n.color,
            key: left.key.clone(),
            value: left.value.clone(),
            left: left.left.clone(),
            right: Some(Rc::new(Node {
                color: Color::Red,
                key: n.key.clone(),
                value: n.value.clone(),
                left: left.right.clone(),
                right: n.right.clone(),
            })),
        })
    }

    /// Flip colors for current node and children.
    fn flip_colors(node: Rc<Node<K, V>>) -> Rc<Node<K, V>> {
        let n = &*node;
        Rc::new(Node {
            color: Color::Red,
            key: n.key.clone(),
            value: n.value.clone(),
            left: n.left.as_ref().map(|l| Self::set_color(l.clone(), Color::Black)),
            right: n.right.as_ref().map(|r| Self::set_color(r.clone(), Color::Black)),
        })
    }

    fn set_color(node: Rc<Node<K, V>>, color: Color) -> Rc<Node<K, V>> {
        let n = &*node;
        Rc::new(Node {
            color,
            key: n.key.clone(),
            value: n.value.clone(),
            left: n.left.clone(),
            right: n.right.clone(),
        })
    }

    /// In-order iterator.
    pub fn iter(&self) -> RBTreeIter<K, V> {
        RBTreeIter::new(self.root.clone())
    }
}

/// Iterator for RBTree (in-order).
pub struct RBTreeIter<K, V> {
    stack: Vec<Rc<Node<K, V>>>,
}

impl<K: Ord, V> RBTreeIter<K, V> {
    fn new(root: Option<Rc<Node<K, V>>>) -> Self {
        let mut stack = Vec::new();
        let mut n = root;
        while let Some(node) = n {
            stack.push(node.clone());
            n = node.left.clone();
        }
        RBTreeIter { stack }
    }
}

impl<K: Ord, V> Iterator for RBTreeIter<K, V> {
    type Item = (K, V);

    fn next(&mut self) -> Option<Self::Item> {
        if let Some(node) = self.stack.pop() {
            let mut n = node.right.clone();
            while let Some(nd) = n {
                self.stack.push(nd.clone());
                n = nd.left.clone();
            }
            Some((node.key.clone(), node.value.clone()))
        } else {
            None
        }
    }
}

// ----------- Example Usage -----------

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn basic_insert_get() {
        let t = RBTree::<i32, &str>::new();
        let t2 = t.insert(1, "one");
        let t3 = t2.insert(2, "two");
        assert_eq!(t.get(&1), None);
