Sure! Here's a simple SQL `SELECT` parser in Rust using [`nom`](https://github.com/ToothlessRebel/nom) (a popular parsing library). This parser will handle basic queries like:

```sql
SELECT col1, col2 FROM my_table;
SELECT * FROM users WHERE age > 30;
```

### Features

- Parses a list of columns or `*`
- Recognizes the table name
- Optionally parses a `WHERE` clause (simple expressions)

---

## 1. Add Dependencies

**In `Cargo.toml`:**

```toml
[dependencies]
nom = "7"
```

---

## 2. The Code

```rust
use nom::{
    branch::alt,
    bytes::complete::{tag, take_while1, take_until},
    character::complete::{char, multispace0, multispace1},
    combinator::{map, opt},
    multi::separated_list1,
    sequence::{delimited, preceded, tuple},
    IResult,
};

#[derive(Debug)]
pub struct SelectQuery {
    pub columns: Vec<String>, // ["*"] or ["col1", ...]
    pub table: String,
    pub where_clause: Option<String>,
}

// --- Utilities --- //
fn identifier(input: &str) -> IResult<&str, String> {
    let (rest, id) = take_while1(|c: char| c.is_alphanumeric() || c == '_' || c == '.')(input)?;
    Ok((rest, id.to_string()))
}

// --- Columns Parser --- //
fn columns(input: &str) -> IResult<&str, Vec<String>> {
    let star = map(tag("*"), |_| vec!["*".to_string()]);
    let column_list = separated_list1(
        delimited(multispace0, char(','), multispace0),
        identifier,
    );
    alt((star, column_list))(input)
}

// --- Table Parser --- //
fn table(input: &str) -> IResult<&str, String> {
    preceded(multispace0, identifier)(input)
}

// --- WHERE Clause --- //
fn where_clause(input: &str) -> IResult<&str, String> {
    // Just grab everything after WHERE until end/semicolon
    let (rest, _) = tuple((multispace0, tag("WHERE"), multispace1))(input)?;
    // For simplicity: eat until ';' or end
    let (rest, clause) = take_until(";")(rest).or_else(|_| Ok(("", rest)))?;
    Ok((rest, clause.trim().to_string()))
}

// --- SELECT Parser --- //
pub fn select_parser(input: &str) -> IResult<&str, SelectQuery> {
    let (rest, _) = tuple((multispace0, tag("SELECT"), multispace1))(input)?;
    let (rest, cols) = columns(rest)?;
    let (rest, _) = tuple((multispace0, tag("FROM"), multispace1))(rest)?;
    let (rest, tbl) = table(rest)?;

    let (rest, where_opt) = opt(where_clause)(rest)?;
    // Optionally match trailing spaces and ';'
    let (rest, _) = delimited(multispace0, opt(char(';')), multispace0)(rest)?;

    Ok((
        rest,
        SelectQuery {
            columns: cols,
            table: tbl,
            where_clause: where_opt,
        },
    ))
}

// --- Test --- //
fn main() {
    let queries = [
        "SELECT * FROM users;",
        "SELECT id, name FROM customers WHERE active = 1;",
        "SELECT foo,bar,qux FROM my_table;",
        "SELECT * FROM data WHERE value > 10 AND category = 'A';",
    ];
    for q in queries.iter() {
        match select_parser(q) {
            Ok((_remaining, ast)) => println!("Parsed: {:#?}", ast),
            Err(e) => println!("Error: {:?}", e),
        }
    }
}
```

