```rust
// lamport.rs

/// Lamport timestamp implementation in Rust.
/// Simulates two distributed processes exchanging events.
///
/// To run:
/// `cargo run`
use std::sync::{Arc, Mutex};
use std::thread;

/// Lamport clock for each process.
#[derive(Debug, Clone)]
struct LamportClock {
    time: u64,
}

impl LamportClock {
    /// Create a new Lamport clock, initialized to zero.
    pub fn new() -> Self {
        LamportClock { time: 0 }
    }

    /// Advance the clock for a local event.
    pub fn tick(&mut self) {
        self.time += 1;
    }

    /// Advance the clock based on a remote timestamp.
    pub fn update_receive(&mut self, received_time: u64) {
        self.time = std::cmp::max(self.time, received_time) + 1;
    }

    /// Read current timestamp.
    pub fn now(&self) -> u64 {
        self.time
    }
}

/// Simulate a distributed process with Lamport timestamps.
struct Process {
    name: String,
    clock: LamportClock,
}

impl Process {
    pub fn new(name: &str) -> Self {
        Process {
            name: name.to_string(),
            clock: LamportClock::new(),
        }
    }

    /// Perform a local event.
    pub fn local_event(&mut self) {
        self.clock.tick();
        println!(
            "[{}] Local event at Lamport time {}",
            self.name,
            self.clock.now()
        );
    }

    /// Send a message (with timestamp).
    pub fn send_event(&mut self) -> u64 {
        self.clock.tick();
        println!(
            "[{}] Send event at Lamport time {}",
            self.name,
            self.clock.now()
        );
        self.clock.now()
    }

    /// Receive a message.
    pub fn receive_event(&mut self, received_time: u64) {
        self.clock.update_receive(received_time);
        println!(
            "[{}] Receive event (received {}) at Lamport time {}",
            self.name,
            received_time,
            self.clock.now()
        );
    }
}

fn main() {
    let p1 = Arc::new(Mutex::new(Process::new("P1")));
    let p2 = Arc::new(Mutex::new(Process::new("P2")));

    // Simulate events, message exchange between two "processes"
    let p1_thread = {
        let p1 = Arc::clone(&p1);
        let p2 = Arc::clone(&p2);
        thread::spawn(move || {
            let mut p1 = p1.lock().unwrap();
            p1.local_event();              // Event 1 (local)
            let msg_time = p1.send_event(); // Event 2 (send to P2)

            drop(p1);

            // Simulate sending msg_time to p2
            let mut p2 = p2.lock().unwrap();
            p2.receive_event(msg_time); // Event 3 (receive by P2)
            p2.local_event();           // Event 4 (local event P2)
        })
    };

    let p2_thread = {
        let p1 = Arc::clone(&p1);
        let p2 = Arc::clone(&p2);
        thread::spawn(move || {
            // Wait for P1 to send first
            thread::sleep(std::time::Duration::from_millis(10));

            let mut p2 = p2.lock().unwrap();
            let msg_time = p2.send_event(); // Event 5 (send to P1)

            drop(p2);

            // Simulate sending msg_time to p1
            let mut p1 = p1.lock().unwrap();
            p1.receive_event(msg_time); // Event 6 (receive by P1)
        })
    };

    p1_thread.join().unwrap();
    p2_thread.join().unwrap();

    println!("\nFinal timestamps:");
    let p1 = p1.lock().unwrap();
    let p2 = p2.lock().unwrap();
    println!("P1 Lamport time: {}", p1.clock.now());
    println!("P2 Lamport time: {}", p2.clock.now());
}
```

---

### How it works

- Each process (`P1`, `P2`) maintains its own Lamport timestamp in `LamportClock`.
- Local and sent events increment the clock.
- Receiving an event updates the clock to `max(local, received) + 1`.
- The main function simulates two threads, each acting as a process, sending and receiving messages between them.

---

### Output Example

```
[P1] Local event at Lamport time 1
[P1] Send event at Lamport time 2
[P2] Receive event (received 2) at Lamport time 3
[P2] Local event at Lamport time 4
[P2] Send event at Lamport time 5
[P1] Receive event (received 5) at Lamport time 6

Final timestamps:
P1 Lamport time: 6
P2 Lamport time: 5
```

