Certainly! Here’s a **complete, working Rust implementation** for solving the N-Queens problem (printing all solutions).

This code defines a function that returns all distinct solutions and prints them in a readable format.

```rust
fn solve_n_queens(n: usize) -> Vec<Vec<String>> {
    fn backtrack(
        n: usize,
        row: usize,
        cols: &mut Vec<bool>,
        diag1: &mut Vec<bool>,
        diag2: &mut Vec<bool>,
        path: &mut Vec<usize>,
        res: &mut Vec<Vec<String>>,
    ) {
        if row == n {
            // Formulate solution
            let solution = path
                .iter()
                .map(|&col| {
                    let mut line = vec!['.'; n];
                    line[col] = 'Q';
                    line.into_iter().collect()
                })
                .collect();
            res.push(solution);
            return;
        }
        for col in 0..n {
            let d1 = row + col;
            let d2 = n + row - col;
            if cols[col] || diag1[d1] || diag2[d2] {
                continue;
            }
            cols[col] = true;
            diag1[d1] = true;
            diag2[d2] = true;
            path.push(col);
            backtrack(n, row + 1, cols, diag1, diag2, path, res);
            path.pop();
            cols[col] = false;
            diag1[d1] = false;
            diag2[d2] = false;
        }
    }

    let mut res = Vec::new();
    let mut cols = vec![false; n];
    let mut diag1 = vec![false; 2 * n];
    let mut diag2 = vec![false; 2 * n];
    let mut path = Vec::new();
    backtrack(
        n,
        0,
        &mut cols,
        &mut diag1,
        &mut diag2,
        &mut path,
        &mut res,
    );
    res
}

fn print_solutions(solutions: &Vec<Vec<String>>) {
    for (i, solution) in solutions.iter().enumerate() {
        println!("Solution {}:", i + 1);
        for line in solution {
            println!("{}", line);
        }
        println!();
    }
}

fn main() {
    let n = 8;
    let solutions = solve_n_queens(n);
    println!("Number of solutions: {}", solutions.len());
    print_solutions(&solutions);
}
```

**How it works:**
- `solve_n_queens` returns a vector of board configurations, each as a vector of strings (rows).
- `print_solutions` prints all found solutions in a readable board format.
- Change `let n = 8;` to your desired value.

