use std::f64::consts::FRAC_1_SQRT_2;

#[derive(Clone)]
struct Qubit([f64; 2]);

impl Qubit {
    fn new() -> Self { Qubit([1.0, 0.0]) }
    fn apply_x(&mut self) {
        let [a, b] = self.0;
        self.0 = [b, a];
    }
    fn apply_h(&mut self) {
        let [a, b] = self.0;
        self.0 = [
            FRAC_1_SQRT_2 * (a + b),
            FRAC_1_SQRT_2 * (a - b)
        ];
    }
    fn measure(&self) -> u8 {
        let prob_0 = self.0[0] * self.0[0];
        if rand::random::<f64>() < prob_0 { 0 } else { 1 }
    }
}

fn main() {
    let mut q = Qubit::new();
    q.apply_h();                // Put qubit into superposition
    let result = q.measure();   // Measure
    println!("Measured: {}", result);
}
