fn is_palindrome(input: &str) -> bool {
    // Filter out non-alphanumeric characters and make lower-case
    let cleaned: String = input.chars()
        .filter(|c| c.is_alphanumeric())
        .map(|c| c.to_ascii_lowercase())
        .collect();

    cleaned == cleaned.chars().rev().collect::<String>()
}

// Example usage:
fn main() {
    let test1 = "A man, a plan, a canal: Panama";
    let test2 = "Rust";
    let test3 = "abba";

    println!("'{}' -> {}", test1, is_palindrome(test1)); // true
    println!("'{}' -> {}", test2, is_palindrome(test2)); // false
    println!("'{}' -> {}", test3, is_palindrome(test3)); // true
}
```

### How it works

- Removes non-alphanumeric characters and converts all to lowercase.
- Compares the cleaned string with its reverse.

---

