```rust
fn binary_search<T: Ord>(arr: &[T], target: &T) -> Option<usize> {
    let mut left = 0;
    let mut right = arr.len();

    while left < right {
        let mid = left + (right - left) / 2;
        if &arr[mid] == target {
            return Some(mid);
        } else if &arr[mid] < target {
            left = mid + 1;
        } else {
            right = mid;
        }
    }
    None
}

fn main() {
    let arr = [1, 3, 5, 7, 9, 11, 13];
    let target = 7;

    match binary_search(&arr, &target) {
        Some(index) => println!("Found {} at index {}", target, index),
        None => println!("{} not found in array", target),
    }

    // Test with a value not in array
    let target2 = 6;
    match binary_search(&arr, &target2) {
        Some(index) => println!("Found {} at index {}", target2, index),
        None => println!("{} not found in array", target2),
    }
}
```

**How it works:**
- The function searches the sorted array for the given target.
- It uses two pointers, `left` and `right` (exclusive), and checks the midpoint for equality, greater, or less than the target.
- Returns the index if found, no index if not found.

