Here’s a complete, working implementation of a Trie data structure in Rust, including insertion, search, and prefix-check operations.

### `trie.rs`

```rust
use std::collections::HashMap;

/// Trie Node definition
#[derive(Default)]
struct TrieNode {
    children: HashMap<char, TrieNode>,
    is_end_of_word: bool,
}

/// The Trie itself
pub struct Trie {
    root: TrieNode,
}

impl Trie {
    /// Create a new Trie
    pub fn new() -> Self {
        Trie {
            root: TrieNode::default(),
        }
    }

    /// Insert a word into the Trie
    pub fn insert(&mut self, word: &str) {
        let mut node = &mut self.root;
        for ch in word.chars() {
            node = node.children.entry(ch).or_insert_with(TrieNode::default);
        }
        node.is_end_of_word = true;
    }

    /// Search for a whole word in the Trie
    pub fn search(&self, word: &str) -> bool {
        let mut node = &self.root;
        for ch in word.chars() {
            match node.children.get(&ch) {
                Some(next_node) => node = next_node,
                None => return false,
            }
        }
        node.is_end_of_word
    }

    /// Check if any word in the Trie starts with the given prefix
    pub fn starts_with(&self, prefix: &str) -> bool {
        let mut node = &self.root;
        for ch in prefix.chars() {
            match node.children.get(&ch) {
                Some(next_node) => node = next_node,
                None => return false,
            }
        }
        true
    }
}

// Optional: Basic tests
#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn trie_operations() {
        let mut trie = Trie::new();
        trie.insert("apple");
        trie.insert("apply");
        trie.insert("app");

        assert!(trie.search("app"));
        assert!(trie.search("apple"));
        assert!(!trie.search("apples"));
        assert!(!trie.search("banana"));

        assert!(trie.starts_with("app"));
        assert!(trie.starts_with("appl"));
        assert!(trie.starts_with("a"));
        assert!(!trie.starts_with("ban"));
    }
}
```

### Usage Example

```rust
