    let mut trie = Trie::new();
    trie.insert("rust");
    trie.insert("rocket");

    println!("Search 'rust': {}", trie.search("rust")); // true
    println!("Search 'rock': {}", trie.search("rock")); // false
    println!("Starts with 'roc': {}", trie.starts_with("roc")); // true
    println!("Starts with 'ru': {}", trie.starts_with("ru")); // true
}
```

