This implementation:
- Uses `std::time` for tracking time.
- Is thread-safe via `Arc<Mutex<_>>`, so you can share the limiter between threads.
- Includes a basic test/example usage case.

---

```rust
use std::sync::{Arc, Mutex};
use std::time::{Duration, Instant};

/// Token Bucket Rate Limiter
pub struct TokenBucket {
    capacity: u32,           // Maximum number of tokens
    tokens: f64,             // Current tokens (can be fractional)
    refill_rate: f64,        // Tokens added per second
    last_refill: Instant,    // Last time tokens were refilled
}

impl TokenBucket {
    /// Create a new TokenBucket
    ///
    /// # Arguments
    /// * `capacity` - Maximum number of tokens (bucket size)
    /// * `refill_rate` - Number of tokens to add per second
    pub fn new(capacity: u32, refill_rate: f64) -> Self {
        Self {
            capacity,
            tokens: capacity as f64,
            refill_rate,
            last_refill: Instant::now(),
        }
    }

    /// Try to consume `count` tokens.
    /// Returns true if tokens are available, false otherwise.
    pub fn try_consume(&mut self, count: u32) -> bool {
        self.refill();

        if self.tokens >= count as f64 {
            self.tokens -= count as f64;
            true
        } else {
            false
        }
    }

    /// Refill tokens based on elapsed time.
    fn refill(&mut self) {
        let now = Instant::now();
        let elapsed = now.duration_since(self.last_refill);

        let added = self.refill_rate * elapsed.as_secs_f64();
        if added > 0.0 {
            self.tokens = (self.tokens + added).min(self.capacity as f64);
            self.last_refill = now;
        }
    }
}

/// Thread-safe wrapper
pub type SharedTokenBucket = Arc<Mutex<TokenBucket>>;

/// Example usage
fn main() {
    let capacity = 5;
    let refill_per_sec = 2.0;
    let bucket = Arc::new(Mutex::new(TokenBucket::new(capacity, refill_per_sec)));

    // Simulate incoming requests
    for i in 1..10 {
        let mut bucket = bucket.lock().unwrap();
        if bucket.try_consume(1) {
            println!("Request {} allowed", i);
        } else {
            println!("Request {} denied (rate limited)", i);
        }
        std::thread::sleep(Duration::from_millis(300));
    }

    // Wait to refill
    std::thread::sleep(Duration::from_secs(3));
    let mut bucket = bucket.lock().unwrap();
    if bucket.try_consume(1) {
        println!("Request after refill allowed");
    } else {
        println!("Request after refill denied");
    }
}

```

---

**How it works:**
- The bucket starts full (capacity tokens).
- Each call to `try_consume` first refills tokens based on time elapsed.
- If enough tokens, consume and allow; else, deny.
- The example demonstrates usage (and refill after waiting).

