Here is a complete implementation of a **bounded blocking queue** in Rust, using `std::sync::{Mutex, Condvar}` for thread safety and blocking behavior.

---

### `BoundedBlockingQueue<T>`

- **Features:**
  - Fixed capacity.
  - `push` blocks if the queue is full.
  - `pop` blocks if the queue is empty.
  - Safe for multi-threaded use.

---

```rust
use std::collections::VecDeque;
use std::sync::{Arc, Mutex, Condvar};
use std::time::{Duration, Instant};

/// A thread-safe bounded blocking queue.
pub struct BoundedBlockingQueue<T> {
    inner: Arc<QueueInner<T>>,
}

struct QueueInner<T> {
    queue: Mutex<VecDeque<T>>,
    not_full: Condvar,
    not_empty: Condvar,
    capacity: usize,
}

impl<T> BoundedBlockingQueue<T> {
    /// Creates a new queue with the given capacity.
    pub fn new(capacity: usize) -> Self {
        assert!(capacity > 0);
        Self {
            inner: Arc::new(QueueInner {
                queue: Mutex::new(VecDeque::with_capacity(capacity)),
                not_full: Condvar::new(),
                not_empty: Condvar::new(),
                capacity,
            }),
        }
    }

    /// Adds an item to the queue. Blocks if full.
    pub fn push(&self, item: T) {
        let mut queue = self.inner.queue.lock().unwrap();
        while queue.len() == self.inner.capacity {
            queue = self.inner.not_full.wait(queue).unwrap();
        }
        queue.push_back(item);
        // Notify threads waiting for items.
        self.inner.not_empty.notify_one();
    }

    /// Removes and returns an item from the queue. Blocks if empty.
    pub fn pop(&self) -> T {
        let mut queue = self.inner.queue.lock().unwrap();
        while queue.is_empty() {
            queue = self.inner.not_empty.wait(queue).unwrap();
        }
        let item = queue.pop_front().unwrap();
        // Notify threads waiting to push items.
        self.inner.not_full.notify_one();
        item
    }

    /// Returns the current number of elements.
    pub fn len(&self) -> usize {
        self.inner.queue.lock().unwrap().len()
    }

    /// Returns the capacity.
    pub fn capacity(&self) -> usize {
        self.inner.capacity
    }

    /// Returns whether the queue is empty.
    pub fn is_empty(&self) -> bool {
        self.len() == 0
    }

    /// Returns whether the queue is full.
    pub fn is_full(&self) -> bool {
        self.len() == self.inner.capacity
    }

    /// Try to push an item within a timeout. Returns Ok(()) on success, Err(item) if timeout.
    pub fn try_push(&self, item: T, timeout: Duration) -> Result<(), T> {
        let mut queue = self.inner.queue.lock().unwrap();
        let deadline = Instant::now() + timeout;
        while queue.len() == self.inner.capacity {
            let now = Instant::now();
            if now >= deadline {
                return Err(item);
            }
            let wait_for = deadline - now;
            let (guard, result) = self.inner.not_full.wait_timeout(queue, wait_for).unwrap();
            queue = guard;
            if result.timed_out() && queue.len() == self.inner.capacity {
                return Err(item);
            }
        }
        queue.push_back(item);
        self.inner.not_empty.notify_one();
        Ok(())
    }

    /// Try to pop an item within a timeout. Returns Some(item) on success, None if timeout.
    pub fn try_pop(&self, timeout: Duration) -> Option<T> {
        let mut queue = self.inner.queue.lock().unwrap();
        let deadline = Instant::now() + timeout;
        while queue.is_empty() {
            let now = Instant::now();
            if now >= deadline {
                return None;
            }
            let wait_for = deadline - now;
            let (guard, result) = self.inner.not_empty.wait_timeout(queue, wait_for).unwrap();
            queue = guard;
            if result.timed_out() && queue.is_empty() {
                return None;
            }
        }
        let item = queue.pop_front().unwrap();
        self.inner.not_full.notify_one();
        Some(item)
    }
}

