    use std::thread;

    #[test]
    fn test_basic_push_pop() {
        let queue = BoundedBlockingQueue::new(2);
        queue.push(1);
        queue.push(2);
        assert!(queue.is_full());
        let v1 = queue.pop();
        assert_eq!(v1, 1);
        let v2 = queue.pop();
        assert_eq!(v2, 2);
