            q2.push(42);
            q2.push(43); // will block until the main thread pops
            q2.pop()
        });
        std::thread::sleep(Duration::from_millis(100));
        let v = queue.pop();
        assert_eq!(v, 42);
        queue.push(99); // allow thread to push 43
        let result = handle.join().unwrap();
        assert_eq!(result, 43);
