```rust
use std::str::Chars;

#[derive(Debug, PartialEq)]
enum Token {
    Number(f64),
    Plus,
    Minus,
    Mul,
    Div,
    LParen,
    RParen,
}

struct Lexer<'a> {
    input: Chars<'a>,
    peeked: Option<char>,
}

impl<'a> Lexer<'a> {
    fn new(input: &'a str) -> Self {
        Self {
            input: input.chars(),
            peeked: None,
        }
    }

    fn next_char(&mut self) -> Option<char> {
        if let Some(c) = self.peeked.take() {
            Some(c)
        } else {
            self.input.next()
        }
    }

    fn peek_char(&mut self) -> Option<char> {
        if self.peeked.is_none() {
            self.peeked = self.input.next();
        }
        self.peeked
    }

    fn skip_whitespace(&mut self) {
        while let Some(c) = self.peek_char() {
            if c.is_whitespace() {
                self.next_char();
            } else {
                break;
            }
        }
    }

    fn next_token(&mut self) -> Option<Token> {
        self.skip_whitespace();
        let c = self.next_char()?;

        match c {
            '+' => Some(Token::Plus),
            '-' => Some(Token::Minus),
            '*' => Some(Token::Mul),
            '/' => Some(Token::Div),
            '(' => Some(Token::LParen),
            ')' => Some(Token::RParen),
            '0'..='9' | '.' => {
                let mut num_str = String::new();
                num_str.push(c);
                while let Some(&next_c) = self.peek_char().as_ref() {
                    if next_c.is_ascii_digit() || next_c == '.' {
                        num_str.push(self.next_char().unwrap());
                    } else {
                        break;
                    }
                }
                let number = num_str.parse::<f64>().unwrap();
                Some(Token::Number(number))
            }
            _ => None, // Invalid character
        }
    }

    fn tokenize(mut self) -> Vec<Token> {
        let mut tokens = Vec::new();
        while let Some(tok) = self.next_token() {
            tokens.push(tok);
        }
        tokens
    }
}

// Parser using Shunting-Yard algorithm to build RPN and then evaluates
fn precedence(token: &Token) -> u8 {
    match token {
        Token::Plus | Token::Minus => 1,
        Token::Mul | Token::Div => 2,
        _ => 0,
    }
}

fn eval_expr(expr: &str) -> Result<f64, String> {
    let lexer = Lexer::new(expr);
    let tokens = lexer.tokenize();

    // Convert to Reverse Polish Notation (RPN)
    let mut output = Vec::new();
    let mut ops = Vec::new();

    for token in tokens {
        match token {
            Token::Number(_) => output.push(token),
            Token::Plus | Token::Minus | Token::Mul | Token::Div => {
                while let Some(top) = ops.last() {
                    if (matches!(top, Token::Plus | Token::Minus | Token::Mul | Token::Div))
                        && precedence(top) >= precedence(&token)
                    {
                        output.push(ops.pop().unwrap());
                    } else {
                        break;
                    }
                }
                ops.push(token);
            }
            Token::LParen => ops.push(token),
            Token::RParen => {
                while let Some(top) = ops.last() {
                    if *top == Token::LParen {
                        break;
                    } else {
                        output.push(ops.pop().unwrap());
                    }
                }
                if ops.last() == Some(&Token::LParen) {
                    ops.pop();
                } else {
                    return Err("Mismatched parentheses".to_string());
                }
            }
        }
    }
    while let Some(top) = ops.pop() {
        if top == Token::LParen || top == Token::RParen {
            return Err("Mismatched parentheses".to_string());
        }
        output.push(top);
    }

    // Evaluate the RPN expression
    let mut stack = Vec::new();
    for token in output {
        match token {
            Token::Number(n) => stack.push(n),
            Token::Plus => {
                let b = stack.pop().ok_or("Invalid expression")?;
                let a = stack.pop().ok_or("Invalid expression")?;
                stack.push(a + b);
            }
            Token::Minus => {
                let b = stack.pop().ok_or("Invalid expression")?;
                let a = stack.pop().ok_or("Invalid expression")?;
                stack.push(a - b);
            }
            Token::Mul => {
                let b = stack.pop().ok_or("Invalid expression")?;
                let a = stack.pop().ok_or("Invalid expression")?;
                stack.push(a * b);
            }
            Token::Div => {
                let b = stack.pop().ok_or("Invalid expression")?;
                let a = stack.pop().ok_or("Invalid expression")?;
                stack.push(a / b);
            }
            _ => return Err("Invalid token in RPN".to_string()),
        }
    }
    if stack.len() == 1 {
        Ok(stack[0])
    } else {
        Err("Invalid expression".to_string())
    }
}

// Example main function
fn main() {
    let examples = [
        "2 + 3 * 4",
        "(1 + 2) * 3",
        "10 / (4 - 2)",
        "3.5 * (2 + 7)",
        "-1 + 5",
        "2 * (3 + (4 * 5))",
        "3 + 4 * 2 / (1 - 5)"
    ];
    for expr in examples.iter() {
        match eval_expr(expr) {
            Ok(result) => println!("{} = {}", expr, result),
            Err(e) => println!("{} : ERROR - {}", expr, e),
        }
    }
}
```

