**`src/main.rs`:**

```rust
fn is_match(s: &str, p: &str) -> bool {
    fn helper(s: &[u8], p: &[u8]) -> bool {
        if p.is_empty() {
            return s.is_empty();
        }

        let first_match = !s.is_empty() &&
            (p[0] == b'.' || p[0] == s[0]);

        if p.len() >= 2 && p[1] == b'*' {
            // Two cases:
            // 1. Skip the x* (move p forward by 2)
            // 2. If first matches, use the '*' to consume one char from s
            return helper(s, &p[2..]) ||
                (first_match && helper(&s[1..], p));
        } else {
            return first_match && helper(&s[1..], &p[1..]);
        }
    }
    helper(s.as_bytes(), p.as_bytes())
}

// Simple testing harness
fn main() {
    let tests = [
        ("aa", "a", false),
        ("aa", "a*", true),
        ("ab", ".*", true),
        ("aab", "c*a*b", true),
        ("mississippi", "mis*is*p*.", false),
        ("", ".*", true),
        ("", "a*", true),
        ("ab", ".*c", false),
    ];

    for (s, p, expected) in &tests {
        let result = is_match(s, p);
        println!("is_match({:?}, {:?}) = {} (expected {})", s, p, result, expected);
        assert_eq!(result, *expected);
    }
    println!("All tests passed!");
}
```

