```rust
use std::fmt::Debug;

// Minimum degree (t): Each node except root must have at least t-1 keys.
// Each node can have at most 2*t-1 keys.
const MIN_DEGREE: usize = 3;

#[derive(Debug)]
struct BTreeNode<K: Ord + Clone + Debug> {
    keys: Vec<K>,
    children: Vec<Box<BTreeNode<K>>>,
    leaf: bool,
}

impl<K: Ord + Clone + Debug> BTreeNode<K> {
    fn new(leaf: bool) -> Self {
        BTreeNode {
            keys: Vec::new(),
            children: Vec::new(),
            leaf,
        }
    }

    fn search(&self, key: &K) -> Option<&K> {
        let mut i = 0;
        while i < self.keys.len() && key > &self.keys[i] {
            i += 1;
        }
        if i < self.keys.len() && &self.keys[i] == key {
            return Some(&self.keys[i]);
        }
        if self.leaf {
            None
        } else {
            self.children[i].search(key)
        }
    }

    // Insert non-full
    fn insert_non_full(&mut self, key: K) {
        let mut i = self.keys.len();
        if self.leaf {
            // Insert key in this node
            self.keys.push(key.clone()); // Temporary push to extend Vec
            while i > 0 && self.keys[i - 1] > key {
                self.keys[i] = self.keys[i - 1].clone();
                i -= 1;
            }
            self.keys[i] = key;
        } else {
            // Find child to insert
            while i > 0 && self.keys[i - 1] > key {
                i -= 1;
            }
            if self.children[i].keys.len() == 2 * MIN_DEGREE - 1 {
                // If child is full, split
                self.split_child(i);
                if self.keys[i] < key {
                    i += 1;
                }
            }
            self.children[i].insert_non_full(key);
        }
    }

    // Split full child at children[i]
    fn split_child(&mut self, i: usize) {
        let full = &mut self.children[i];
        let mut new = BTreeNode::new(full.leaf);

        // Move MIN_DEGREE-1 keys to new node
        new.keys = full.keys.split_off(MIN_DEGREE);
        // Middle key
        let mid = full.keys.pop().unwrap();

        if !full.leaf {
            // Move MIN_DEGREE children to new node
            new.children = full.children.split_off(MIN_DEGREE);
        }

        self.keys.insert(i, mid);
        self.children.insert(i + 1, Box::new(new));
    }

    fn print(&self, depth: usize) {
        print!("{}[", "  ".repeat(depth));
        for k in &self.keys {
            print!("{:?} ", k);
        }
        println!("]");
        if !self.leaf {
            for child in &self.children {
                child.print(depth + 1);
            }
        }
    }
}


#[derive(Debug)]
pub struct BTree<K: Ord + Clone + Debug> {
    root: Option<Box<BTreeNode<K>>>,
}

impl<K: Ord + Clone + Debug> BTree<K> {
    pub fn new() -> Self {
        BTree { root: None }
    }

    pub fn search(&self, key: &K) -> Option<&K> {
        match &self.root {
            Some(root) => root.search(key),
            None => None,
        }
    }

    pub fn insert(&mut self, key: K) {
        if self.root.is_none() {
            let mut root = BTreeNode::new(true);
            root.keys.push(key);
            self.root = Some(Box::new(root));
            return;
        }

        let root = self.root.as_mut().unwrap();
        if root.keys.len() == 2 * MIN_DEGREE - 1 {
            // Root is full; split.
            let mut new_root = BTreeNode::new(false);
            new_root.children.push(Box::new(root.clone()));
            new_root.split_child(0);

            self.root = Some(Box::new(new_root));
            // Insert in new root
            self.root.as_mut().unwrap().insert_non_full(key);
        } else {
            root.insert_non_full(key);
        }
    }

    pub fn print(&self) {
        if let Some(root) = &self.root {
            root.print(0);
        }
    }
}

fn main() {
    let mut btree = BTree::<i32>::new();

    let values = vec![
        10, 20, 5, 6, 12, 30, 7, 17,
        2, 40, 50, 3, 19, 4, 1, 60,
    ];

    for v in &values {
        btree.insert(*v);
    }

    println!("B-Tree structure:");
    btree.print();

    println!("\nSearch test:");
    for search_val in [6, 15, 30, 1, 99] {
        match btree.search(&search_val) {
            Some(k) => println!("Found {} in B-tree.", k),
            None => println!("{} not found.", search_val),
        }
    }
}
```

---

**How it works:**
- `MIN_DEGREE` controls the order of the B-tree. Each node except the root has at least `MIN_DEGREE-1` keys, and at most `2*MIN_DEGREE-1`.
- The insertion algorithm splits full nodes and maintains B-tree properties.
- The `print()` function displays the B-tree structure.

