    },
    Vote {
        term: u64,
        vote_granted: bool,
        from_id: usize,
    },
    Heartbeat {
        term: u64,
        leader_id: usize,
    },
}

#[derive(Debug, PartialEq)]
enum State {
    Follower,
    Candidate,
    Leader,
}

struct RaftNode {
    id: usize,
    state: State,
    term: u64,
    voted_for: Option<usize>,
    peers: Vec<Sender<Message>>, // channels to other nodes
    rx: Receiver<Message>,       // receive channel
}

impl RaftNode {
    fn run(mut self) {
        let mut rng = rand::thread_rng();
        let mut last_heartbeat = Instant::now();

        loop {
            match self.state {
                State::Follower => {
                    let election_timeout = Duration::from_millis(
                        rng.gen_range(ELECTION_TIMEOUT_MIN..=ELECTION_TIMEOUT_MAX)
                    );
                    let mut timed_out = false;

                    // Wait for messages or election timeout
                    while !timed_out {
                        if let Ok(msg) = self.rx.recv_timeout(election_timeout) {
                            match msg {
                                Message::RequestVote { term, candidate_id, reply_to } => {
                                    if term > self.term {
                                        self.term = term;
                                        self.voted_for = None;
                                    }
                                    let vote = if term == self.term && (self.voted_for.is_none() || self.voted_for == Some(candidate_id)) {
                                        self.voted_for = Some(candidate_id);
                                        true
                                    } else {
                                        false
                                    };
                                    let _ = reply_to.send(Message::Vote {
                                        term: self.term,
                                        vote_granted: vote,
                                        from_id: self.id,
                                    });
                                }
                                Message::Heartbeat { term, leader_id } => {
                                    if term >= self.term {
                                        self.term = term;
                                        self.voted_for = None;
                                        last_heartbeat = Instant::now();
                                    }
                                }
                                _ => {}
                            }
                        } else {
                            timed_out = true;
                        }
                    }
                    self.state = State::Candidate;
                }

                State::Candidate => {
                    self.term += 1;
                    self.voted_for = Some(self.id);
                    let mut votes = 1;

                    let mut reply_channels = Vec::new();
                    // Send RequestVote RPCs to all peers
                    for peer in &self.peers {
                        let (reply_tx, reply_rx) = mpsc::channel();
                        reply_channels.push(reply_rx);
                        let _ = peer.send(Message::RequestVote {
                            term: self.term,
                            candidate_id: self.id,
                            reply_to: reply_tx,
                        });
                    }

                    let election_deadline = Instant::now() +
                        Duration::from_millis(rng.gen_range(ELECTION_TIMEOUT_MIN..=ELECTION_TIMEOUT_MAX));
                    let mut got_majority = false;

                    while Instant::now() < election_deadline && !got_majority {
                        // Check for votes
                        for rx in &reply_channels {
                            if let Ok(Message::Vote { term, vote_granted, .. }) = rx.try_recv() {
                                if term > self.term {
                                    self.term = term;
                                    self.state = State::Follower;
                                    break;
                                }
                                if vote_granted {
                                    votes += 1;
                                    if votes > NUM_NODES / 2 {
                                        got_majority = true;
                                        break;
                                    }
                                }
                            }
                        }

                        // Also check incoming messages (heartbeats), return to Follower if necessary
                        if let Ok(msg) = self.rx.try_recv() {
                            match msg {
                                Message::Heartbeat { term, leader_id } => {
                                    if term >= self.term {
                                        self.term = term;
                                        self.state = State::Follower;
                                        self.voted_for = None;
                                        break;
                                    }
                                }
                                Message::RequestVote { term, candidate_id, reply_to } => {
                                    if term > self.term {
                                        self.term = term;
                                        self.voted_for = None;
                                    }
                                    let vote = if term == self.term && (self.voted_for.is_none() || self.voted_for == Some(candidate_id)) {
                                        self.voted_for = Some(candidate_id);
                                        true
                                    } else {
                                        false
                                    };
                                    let _ = reply_to.send(Message::Vote {
                                        term: self.term,
                                        vote_granted: vote,
                                        from_id: self.id,
                                    });
                                }
                                _ => {}
                            }
                        }
                        thread::sleep(Duration::from_millis(10));
                    }

                    if got_majority {
                        println!("Node {} becomes Leader in term {}", self.id, self.term);
                        self.state = State::Leader;
                    } else {
                        self.state = State::Follower;
                    }
                }

                State::Leader => {
                    // Send heartbeats to all peers
                    for peer in &self.peers {
                        let _ = peer.send(Message::Heartbeat {
                            term: self.term,
                            leader_id: self.id,
                        });
                    }
                    thread::sleep(Duration::from_millis(HEARTBEAT_INTERVAL));

                    // Handle incoming messages (e.g., higher term RequestVote)
                    while let Ok(msg) = self.rx.try_recv() {
                        match msg {
                            Message::RequestVote { term, candidate_id, reply_to } => {
                                if term > self.term {
                                    self.term = term;
                                    self.state = State::Follower;
                                    self.voted_for = None;
                                    let vote = true;
                                    let _ = reply_to.send(Message::Vote {
                                        term: self.term,
                                        vote_granted: vote,
                                        from_id: self.id,
                                    });
                                    println!("Leader {} stepping down, new term {}", self.id, self.term);
                                    break;
                                } else {
                                    // Deny vote if term is not higher
                                    let _ = reply_to.send(Message::Vote {
                                        term: self.term,
                                        vote_granted: false,
                                        from_id: self.id,
                                    });
                                }
                            }
                            Message::Heartbeat { term, leader_id } => {
                                if term > self.term {
                                    self.term = term;
                                    self.state = State::Follower;
                                    self.voted_for = None;
                                    println!("Leader {} stepping down, new leader {} term {}", self.id, leader_id, term);
                                    break;
                                }
                            }
                            _ => {}
                        }
                    }
                }
            }
        }
    }
}

fn main() {
    let mut nodes = Vec::new();
    let mut handles = Vec::new();
    let mut txs = Vec::new();

    // Create channels for each node
    for _ in 0..NUM_NODES {
        let (tx, rx) = mpsc::channel();
        txs.push(tx);
        nodes.push(rx);
    }

    for i in 0..NUM_NODES {
        let rx = nodes[i].clone();
        let mut peer_txs = Vec::new();
        for j in 0..NUM_NODES {
            if i != j {
                peer_txs.push(txs[j].clone());
            }
        }

        let raft_node = RaftNode {
            id: i,
            state: State::Follower,
            term: 0,
            voted_for: None,
            peers: peer_txs,
            rx,
        };

        handles.push(thread::spawn(move || {
            raft_node.run();
        }));
    }

    // Let cluster run for a while
    thread::sleep(Duration::from_secs(10));
    println!("Done.");
}
```

---

## Notes

- This code demonstrates **leader election** only (not log replication).
- Each node runs in a separate thread.
- Communication is via Rust channel (`mpsc`).
- Randomized election timeouts simulate real network partitions and prevent split votes.
- Log output indicates when nodes become leaders or step down.

**To run:**
1. Save as `main.rs`.
2. Add `rand` crate to your `Cargo.toml`:
   ```toml
   rand = "0.8"
   ```
3. Run via `cargo run`.

