use std::str::FromStr;

#[derive(Debug)]
struct SelectStatement {
    columns: Vec<String>,
    table: String,
    where_clause: Option<WhereClause>,
}

#[derive(Debug)]
struct WhereClause {
    column: String,
    value: String,
}

#[derive(Debug)]
enum ParseError {
    InvalidSyntax,
    MissingSelect,
    MissingFrom,
    InvalidWhereClause,
}

fn trim_quotes(s: &str) -> &str {
    let bytes = s.as_bytes();
    if bytes.len() > 1 && (bytes[0] == b'\'' && bytes[bytes.len() - 1] == b'\'') {
        &s[1..bytes.len() - 1]
    } else if bytes.len() > 1 && (bytes[0] == b'"' && bytes[bytes.len() - 1] == b'"') {
        &s[1..bytes.len() - 1]
    } else {
        s
    }
}

impl FromStr for SelectStatement {
    type Err = ParseError;

    fn from_str(query: &str) -> Result<Self, Self::Err> {
        let query = query.trim().trim_end_matches(';');

        let mut rest = query;

        // Must start with SELECT
        if !rest.to_uppercase().starts_with("SELECT ") {
            return Err(ParseError::MissingSelect);
        }
        rest = &rest[6..].trim_start();

        // Find FROM
        let from_pos = rest.to_uppercase().find(" FROM ");
        if from_pos.is_none() {
            return Err(ParseError::MissingFrom);
        }
        let from_pos = from_pos.unwrap();

        let columns_part = &rest[..from_pos].trim();
        let columns: Vec<String> = columns_part
            .split(',')
            .map(|s| s.trim().to_string())
            .collect();

        rest = &rest[from_pos + 6..].trim_start();

        // Parse table name
        let mut table = String::new();
        let mut where_clause = None;

        // Check for WHERE
        let where_pos = rest.to_uppercase().find(" WHERE ");
        if let Some(w_pos) = where_pos {
            table = rest[..w_pos].trim().to_string();
            let wc_rest = &rest[w_pos + 7..].trim();

            // Only support "col = value"
            let eq_pos = wc_rest.find('=');
            if let Some(eq_pos) = eq_pos {
                let col = wc_rest[..eq_pos].trim().to_string();
                let val = trim_quotes(wc_rest[eq_pos + 1..].trim()).to_string();

                where_clause = Some(WhereClause {
                    column: col,
                    value: val,
                });
            } else {
                return Err(ParseError::InvalidWhereClause);
            }
        } else {
            // No WHERE; all remaining is table name
            table = rest.trim().to_string();
        }

        Ok(SelectStatement {
            columns,
            table,
            where_clause,
        })
    }
}

fn main() {
    let sql = "SELECT name, age FROM users WHERE id = '123';";
    match SelectStatement::from_str(sql) {
        Ok(statement) => {
            println!("Parsed SELECT statement:");
            println!("{:#?}", statement);
        }
        Err(e) => {
            println!("Failed to parse: {:?}", e);
        }
    }

    // Try without WHERE
    let sql2 = "SELECT name FROM users;";
    match SelectStatement::from_str(sql2) {
        Ok(statement) => {
            println!("Parsed SELECT statement:");
            println!("{:#?}", statement);
        }
        Err(e) => {
            println!("Failed to parse: {:?}", e);
        }
    }
}
```

