Certainly! Below is a **complete, working skip list implementation in Rust**. This skip list supports insertion, search, and deletion of ordered key-value pairs. It's generic over key (`K: Ord`) and value (`V`). For simplicity, it uses a fixed maximum level and random level assignment via Rust's `rand` crate.

---

**Cargo.toml** (needed for `rand`):

```toml
[dependencies]
rand = "0.8"
```

---

**src/main.rs**:

```rust
use rand::Rng;
use std::cmp::Ordering;
use std::fmt::Debug;
use std::ptr::null_mut;

// Configuration
const MAX_LEVEL: usize = 16;
const P: f64 = 0.5;

// Definition of a skip list node
struct Node<K, V> {
    key: Option<K>,
    value: Option<V>,
    forwards: Vec<*mut Node<K, V>>,
}

impl<K, V> Node<K, V> {
    fn new(key: Option<K>, value: Option<V>, level: usize) -> Self {
        Node {
            key,
            value,
            forwards: vec![null_mut(); level],
        }
    }
}

pub struct SkipList<K: Ord + Debug, V: Debug> {
    head: *mut Node<K, V>,
    level: usize,
}

impl<K: Ord + Debug, V: Debug> SkipList<K, V> {
    pub fn new() -> Self {
        let head = Box::into_raw(Box::new(Node::new(None, None, MAX_LEVEL)));
        SkipList { head, level: 1 }
    }

    fn random_level(&self) -> usize {
        let mut lvl = 1;
        let mut rng = rand::thread_rng();
        while rng.gen::<f64>() < P && lvl < MAX_LEVEL {
            lvl += 1;
        }
        lvl
    }

    pub fn insert(&mut self, key: K, value: V) {
        unsafe {
            let mut update: Vec<*mut Node<K, V>> = vec![self.head; MAX_LEVEL];
            let mut x = self.head;

            // Find positions to update at each level
            for i in (0..self.level).rev() {
                while let Some(node_key) = (*x).forwards[i].as_ref().and_then(|node| node.key.as_ref()) {
                    if node_key.cmp(&key) == Ordering::Less {
                        x = (*x).forwards[i];
                    } else {
                        break;
                    }
                }
                update[i] = x;
            }

            // Next node at level 0
            x = (*x).forwards[0];

            // If found, update value
            if let Some(found) = x.as_ref() {
                if found.key.as_ref() == Some(&key) {
                    (*x).value = Some(value);
                    return;
                }
            }

            // Insert new node
            let lvl = self.random_level();
            if lvl > self.level {
                for i in self.level..lvl {
                    update[i] = self.head;
                }
                self.level = lvl;
            }

            let mut new_node = Box::new(Node::new(Some(key), Some(value), lvl));
            let new_node_ptr = Box::into_raw(new_node);

            for i in 0..lvl {
                (*new_node_ptr).forwards[i] = (*update[i]).forwards[i];
                (*update[i]).forwards[i] = new_node_ptr;
            }
        }
    }

    pub fn search(&self, key: &K) -> Option<&V> {
        unsafe {
            let mut x = self.head;
            for i in (0..self.level).rev() {
                while let Some(node_key) = (*x).forwards[i].as_ref().and_then(|node| node.key.as_ref()) {
                    if node_key.cmp(key) == Ordering::Less {
                        x = (*x).forwards[i];
                    } else {
                        break;
                    }
                }
            }
            x = (*x).forwards[0];
            if let Some(found) = x.as_ref() {
                if found.key.as_ref() == Some(key) {
                    return found.value.as_ref();
                }
            }
            None
        }
    }

    pub fn delete(&mut self, key: &K) -> bool {
        unsafe {
            let mut update: Vec<*mut Node<K, V>> = vec![self.head; MAX_LEVEL];
            let mut x = self.head;

            for i in (0..self.level).rev() {
                while let Some(node_key) = (*x).forwards[i].as_ref().and_then(|node| node.key.as_ref()) {
                    if node_key.cmp(key) == Ordering::Less {
                        x = (*x).forwards[i];
                    } else {
                        break;
                    }
                }
                update[i] = x;
            }
            x = (*x).forwards[0];

            if let Some(found) = x.as_ref() {
                if found.key.as_ref() == Some(key) {
                    // Remove node from skip list
                    for i in 0..self.level {
                        if (*update[i]).forwards[i] == x {
                            (*update[i]).forwards[i] = (*x).forwards[i];
                        }
                    }
                    // Free the node
                    Box::from_raw(x);

                    // Decrease level if needed
                    while self.level > 1 && (*self.head).forwards[self.level - 1].is_null() {
                        self.level -= 1;
                    }
                    return true;
                }
            }
            false
        }
    }
}

// Memory safety: free all nodes
impl<K: Ord + Debug, V: Debug> Drop for SkipList<K, V> {
    fn drop(&mut self) {
        unsafe {
            let mut x = (*self.head).forwards[0];
            while !x.is_null() {
                let next = (*x).forwards[0];
                Box::from_raw(x);
                x = next;
            }
            Box::from_raw(self.head);
        }
    }
}

// Example usage
fn main() {
    let mut list = SkipList::<i32, &str>::new();

    list.insert(10, "a");
    list.insert(20, "b");
    list.insert(15, "c");

    println!("Search 10: {:?}", list.search(&10));
    println!("Search 15: {:?}", list.search(&15));
    println!("Search 20: {:?}", list.search(&20));
    println!("Search 30: {:?}", list.search(&30));

    list.delete(&15);
    println!("After delete 15, search 15: {:?}", list.search(&15));
}
```

---

### Features

- **SkipList<K, V>:**
  - `insert(key, value)`: Insert or update key-value.
  - `search(key)`: Returns `Option<&V>`.
  - `delete(key)`: Returns `bool` (true if deleted).

- **Drop Implementation:** Ensures all allocated nodes are freed.

- **Unsafe:** Uses raw pointers for efficiency and flexibility. (In a production Rust library, you'd wrap this for full safety.)

---

#### Output Example

```text
Search 10: Some("a")
Search 15: Some("c")
Search 20: Some("b")
Search 30: None
After delete 15, search 15: None
```

