Certainly! Here's a simple quantum computing simulator in Rust under 50 lines. It simulates a single qubit, supports Hadamard (`H`) and Pauli-X (`X`) gates, and measurement:

```rust
use num_complex::Complex;
use rand::random;

type QState = [Complex<f64>; 2];

fn apply_h(q: &mut QState) {
    let h = [
        [Complex::new(1.0 / std::f64::consts::SQRT_2, 0.0), Complex::new(1.0 / std::f64::consts::SQRT_2, 0.0)],
        [Complex::new(1.0 / std::f64::consts::SQRT_2, 0.0), Complex::new(-1.0 / std::f64::consts::SQRT_2, 0.0)]
    ];
    let a = h[0][0]*q[0] + h[0][1]*q[1];
    let b = h[1][0]*q[0] + h[1][1]*q[1];
    q[0] = a; q[1] = b;
}

fn apply_x(q: &mut QState) {
    let tmp = q[0];
    q[0] = q[1];
    q[1] = tmp;
}

fn measure(q: &QState) -> u8 {
    let prob0 = q[0].norm_sqr();
    if random::<f64>() < prob0 {0} else {1}
}

fn main() {
    let mut q = [Complex::new(1.0, 0.0), Complex::new(0.0, 0.0)]; // |0>
    apply_h(&mut q);
    apply_x(&mut q);
    let result = measure(&q);
    println!("Measured: {}", result);
}
```

